BANCO = {
    "manguito_rotador": {
        "nombre": "Manguito Rotador", "nivel": 1, "categoria": "Miembro Superior",
        "preguntas": [
            {"id":"mr_001","concepto":"músculos SITS","enunciado":"¿Cuál de los siguientes NO forma parte del manguito rotador?","opciones":{"A":"Supraespinoso","B":"Infraespinoso","C":"Deltoides","D":"Subescapular"},"correcta":"C","exp":"El manguito rotador = SITS: Supraespinoso, Infraespinoso, Teres minor, Subescapular. El deltoides es extrínseco y no forma parte."},
            {"id":"mr_002","concepto":"músculos SITS","enunciado":"La nemotecnia SITS del manguito rotador corresponde a:","opciones":{"A":"Supraespinoso, Infraespinoso, Teres minor, Subescapular","B":"Subescapular, Infraespinoso, Teres major, Supraespinoso","C":"Supraespinoso, Infraespinoso, Trapecio, Subescapular","D":"Supraespinoso, Iliocostal, Teres minor, Subescapular"},"correcta":"A","exp":"SITS: Supraespinoso (abducción), Infraespinoso (rot. externa), Teres minor (rot. externa), Subescapular (rot. interna). Los 4 estabilizan la cabeza humeral."},
            {"id":"mr_003","concepto":"función supraespinoso","enunciado":"El músculo supraespinoso es el principal responsable de:","opciones":{"A":"Rotación externa del hombro","B":"Inicio de la abducción (0-15°)","C":"Rotación interna del hombro","D":"Aducción del brazo"},"correcta":"B","exp":"El supraespinoso inicia la abducción del hombro en los primeros 0-15°. A partir de 15°, el deltoides toma el relevo. Es el músculo del manguito más frecuentemente lesionado."},
            {"id":"mr_004","concepto":"músculo más lesionado","enunciado":"¿Cuál es el músculo del manguito rotador más frecuentemente lesionado?","opciones":{"A":"Infraespinoso","B":"Teres minor","C":"Supraespinoso","D":"Subescapular"},"correcta":"C","exp":"El supraespinoso es el más lesionado por su paso bajo el arco coracoacromial, donde queda atrapado en la abducción (síndrome de atrapamiento subacromial)."},
            {"id":"mr_005","concepto":"rotación interna","enunciado":"¿Qué músculo del manguito rotador realiza rotación INTERNA del hombro?","opciones":{"A":"Supraespinoso","B":"Infraespinoso","C":"Teres minor","D":"Subescapular"},"correcta":"D","exp":"El subescapular es el único del manguito que hace rotación interna. Se origina en la fosa subescapular de la escápula e inserta en el troquín (tubérculo menor)."},
            {"id":"mr_006","concepto":"inervación","enunciado":"¿Qué nervio inerva el supraespinoso y el infraespinoso?","opciones":{"A":"Nervio axilar","B":"Nervio supraescapular","C":"Nervio subescapular","D":"Nervio musculocutáneo"},"correcta":"B","exp":"El nervio supraescapular (C5-C6) inerva supraespinoso e infraespinoso. El nervio axilar inerva el deltoides y teres minor. El nervio subescapular inerva el subescapular."},
            {"id":"mr_007","concepto":"inervación","enunciado":"El músculo subescapular está inervado por el nervio:","opciones":{"A":"Supraescapular","B":"Axilar","C":"Subescapular superior e inferior","D":"Toracodorsal"},"correcta":"C","exp":"El subescapular está inervado por los nervios subescapulares superior e inferior (ramas del fascículo posterior, C5-C6). No confundir con el nervio supraescapular que inerva supraespinoso e infraespinoso."},
            {"id":"mr_008","concepto":"test clínico","enunciado":"El test de Jobe (empty can test) explora la integridad del:","opciones":{"A":"Infraespinoso","B":"Subescapular","C":"Supraespinoso","D":"Teres minor"},"correcta":"C","exp":"El test de Jobe: hombro abducido 90°, anteversión 30°, rotación interna (pulgar hacia abajo). Se aplica resistencia. Dolor o debilidad = lesión del supraespinoso."},
            {"id":"mr_009","concepto":"rotación externa","enunciado":"Los músculos del manguito que realizan rotación EXTERNA del hombro son:","opciones":{"A":"Supraespinoso y subescapular","B":"Infraespinoso y teres minor","C":"Subescapular y teres minor","D":"Supraespinoso e infraespinoso"},"correcta":"B","exp":"Infraespinoso y teres minor son los rotadores externos del manguito. Ambos se insertan en el troquíter (tubérculo mayor). El infraespinoso es el más potente de los dos."},
            {"id":"mr_010","concepto":"arco coracoacromial","enunciado":"¿Por qué espacio pasa el tendón del supraespinoso?","opciones":{"A":"Canal carpiano","B":"Bajo el arco coracoacromial","C":"Por el canal de Guyon","D":"Sobre el ligamento acromioclavicular"},"correcta":"B","exp":"El tendón del supraespinoso pasa por el espacio subacromial, bajo el arco coracoacromial (acromion + ligamento coracoacromial + apófisis coracoides). La reducción de este espacio causa el síndrome de atrapamiento."},
        ]
    },
    "plexo_braquial": {
        "nombre": "Plexo Braquial", "nivel": 1, "categoria": "Miembro Superior",
        "preguntas": [
            {"id":"pb_001","concepto":"raíces","enunciado":"¿Cuáles son las raíces del plexo braquial?","opciones":{"A":"C4-C5-C6-C7-C8","B":"C5-C6-C7-C8-T1","C":"C4-C5-C6-C7-T1","D":"C5-C6-C7-T1-T2"},"correcta":"B","exp":"El plexo braquial se forma por las ramas anteriores de C5, C6, C7, C8 y T1. Existe variante prefijada (C4-C8) y posfijada (C6-T2), pero la estándar es C5-T1."},
            {"id":"pb_002","concepto":"troncos","enunciado":"¿Cuántos troncos tiene el plexo braquial y cómo se llaman?","opciones":{"A":"2 troncos: superior e inferior","B":"3 troncos: superior, medio e inferior","C":"4 troncos: lateral, medial, posterior y anterior","D":"3 troncos: anterior, medio y posterior"},"correcta":"B","exp":"El plexo tiene 3 troncos: Superior (C5-C6), Medio (C7) e Inferior (C8-T1). Los troncos se dividen en divisiones anteriores y posteriores que forman los fascículos."},
            {"id":"pb_003","concepto":"troncos","enunciado":"El tronco superior del plexo braquial está formado por las raíces:","opciones":{"A":"C5 solo","B":"C5 y C6","C":"C6 y C7","D":"C5, C6 y C7"},"correcta":"B","exp":"Tronco superior = C5 + C6. Tronco medio = C7 (solo). Tronco inferior = C8 + T1. La lesión del tronco superior da la parálisis de Erb-Duchenne."},
            {"id":"pb_004","concepto":"fascículos","enunciado":"¿Cuántos fascículos tiene el plexo braquial?","opciones":{"A":"3 fascículos: lateral, medial y posterior","B":"4 fascículos: anterior, posterior, medial y lateral","C":"2 fascículos: medial y lateral","D":"3 fascículos: superior, medio e inferior"},"correcta":"A","exp":"Los 3 fascículos se nombran por su relación con la arteria axilar: Lateral (divisiones anteriores de troncos sup. y medio), Medial (división anterior del tronco inf.) y Posterior (todas las divisiones posteriores)."},
            {"id":"pb_005","concepto":"parálisis Erb","enunciado":"La parálisis de Erb-Duchenne afecta las raíces:","opciones":{"A":"C8-T1","B":"C5-C6","C":"C7-C8","D":"C5-C6-C7"},"correcta":"B","exp":"Erb-Duchenne = C5-C6 (tronco superior). Causa: tracción forzada del hombro hacia abajo (parto, accidente). Posición típica: 'brazo de camarero': aducción, rotación interna y pronación del antebrazo."},
            {"id":"pb_006","concepto":"parálisis Klumpke","enunciado":"La parálisis de Klumpke afecta las raíces:","opciones":{"A":"C5-C6","B":"C6-C7","C":"C8-T1","D":"C7-C8-T1"},"correcta":"C","exp":"Klumpke = C8-T1 (tronco inferior). Causa: tracción del brazo hacia arriba (parto podálico, colgar del brazo). Produce 'mano en garra' por parálisis de los intrínsecos. Si afecta T1 → síndrome de Horner (ptosis, miosis, anhidrosis)."},
            {"id":"pb_007","concepto":"nervio mediano","enunciado":"¿De qué fascículos proviene el nervio mediano?","opciones":{"A":"Solo del fascículo lateral","B":"Solo del fascículo medial","C":"De los fascículos lateral y medial","D":"Del fascículo posterior"},"correcta":"C","exp":"El nervio mediano tiene dos raíces: una del fascículo lateral (C5-C7) y otra del fascículo medial (C8-T1). Forman la letra M sobre la arteria axilar. Es el único nervio con dos raíces de fascículos diferentes."},
            {"id":"pb_008","concepto":"nervio radial","enunciado":"¿De qué fascículo proviene el nervio radial?","opciones":{"A":"Fascículo lateral","B":"Fascículo medial","C":"Fascículo posterior","D":"Tronco superior directamente"},"correcta":"C","exp":"El nervio radial proviene del fascículo posterior (junto con el axilar). Inerva todos los extensores del brazo y antebrazo. Pasa por el surco de torsión del húmero. Su lesión produce 'mano caída' (wrist drop)."},
            {"id":"pb_009","concepto":"nervio cubital","enunciado":"La lesión del nervio cubital en el codo produce:","opciones":{"A":"Mano caída (wrist drop)","B":"Mano de predicador","C":"Mano en garra (4º y 5º dedos)","D":"Pérdida de flexión del codo"},"correcta":"C","exp":"El nervio cubital (ulnar, del fascículo medial) lesionado en el codo produce garra de los dedos anular y meñique (4º-5º) porque los lumbricales de esos dedos quedan paralizados. La lesión alta en axila da garra de todos los dedos."},
            {"id":"pb_010","concepto":"nervio musculocutáneo","enunciado":"¿Qué inerva el nervio musculocutáneo?","opciones":{"A":"Músculos extensores del codo","B":"Músculos flexores del brazo y piel de antebrazo lateral","C":"Músculos intrínsecos de la mano","D":"Músculo deltoides y teres minor"},"correcta":"B","exp":"El nervio musculocutáneo (del fascículo lateral, C5-C7) inerva: bíceps, braquial anterior y coracobraquial. Continúa como nervio cutáneo lateral del antebrazo (sensitivo). Su lesión es rara aislada."},
        ]
    },
    "huesos_ms": {
        "nombre": "Huesos Miembro Superior", "nivel": 1, "categoria": "Miembro Superior",
        "preguntas": [
            {"id":"hms_001","concepto":"anatomía húmero","enunciado":"¿En qué zona del húmero se inserta el músculo deltoides?","opciones":{"A":"Troquíter (tubérculo mayor)","B":"Troquín (tubérculo menor)","C":"Tuberosidad deltoidea (cara lateral)","D":"Epicóndilo lateral"},"correcta":"C","exp":"El deltoides se inserta en la tuberosidad deltoidea, una rugosidad en la cara anterolateral del cuerpo del húmero, aproximadamente a mitad del hueso."},
            {"id":"hms_002","concepto":"anatomía húmero","enunciado":"¿Qué estructura pasa por el surco bicipital (corredera bicipital) del húmero?","opciones":{"A":"Nervio radial","B":"Tendón de la cabeza larga del bíceps","C":"Arteria axilar","D":"Nervio musculocutáneo"},"correcta":"B","exp":"La corredera bicipital (surco intertubercular) es un canal entre el troquíter y el troquín por donde discurre el tendón de la cabeza larga del bíceps braquial."},
            {"id":"hms_003","concepto":"nervio en surco","enunciado":"El nervio radial discurre por:","opciones":{"A":"Canal carpiano","B":"Surco de torsión (espiral) del húmero","C":"Corredera bicipital","D":"Canal de Guyon"},"correcta":"B","exp":"El nervio radial pasa por el surco de torsión (espiral) en la cara posterior del húmero. Por eso, las fracturas de diáfisis humeral pueden lesionar el nervio radial, produciendo mano caída."},
            {"id":"hms_004","concepto":"anatomía cúbito","enunciado":"El olécranon es una estructura del:","opciones":{"A":"Radio","B":"Húmero","C":"Cúbito","D":"Escafoides"},"correcta":"C","exp":"El olécranon es la prominencia posterior del cúbito que forma el 'codo'. Es la inserción del tríceps braquial. El proceso coronoides del cúbito es la parte anterior que cabe en la fosa coronoidea del húmero."},
            {"id":"hms_005","concepto":"carpo proximal","enunciado":"Los huesos del carpo en la fila PROXIMAL de radial a cubital son:","opciones":{"A":"Trapecio, Trapezoide, Grande, Ganchoso","B":"Escafoides, Semilunar, Piramidal, Pisiforme","C":"Pisiforme, Piramidal, Semilunar, Escafoides","D":"Escafoides, Grande, Piramidal, Pisiforme"},"correcta":"B","exp":"Fila proximal (de radial a cubital): Escafoides - Semilunar - Piramidal - Pisiforme. Fila distal: Trapecio - Trapezoide - Grande - Ganchoso. Nemotecnia: 'El Sábado Por la Tarde Tomamos Gin con Hielo'."},
            {"id":"hms_006","concepto":"carpo distal","enunciado":"Los huesos del carpo en la fila DISTAL de radial a cubital son:","opciones":{"A":"Escafoides, Semilunar, Piramidal, Pisiforme","B":"Grande, Ganchoso, Trapecio, Trapezoide","C":"Trapecio, Trapezoide, Grande, Ganchoso","D":"Trapecio, Grande, Trapezoide, Ganchoso"},"correcta":"C","exp":"Fila distal (de radial a cubital): Trapecio - Trapezoide - Grande - Ganchoso. El Trapecio articula con el 1er metacarpiano (pulgar). El Ganchoso tiene el gancho que se puede palpar en la palma."},
            {"id":"hms_007","concepto":"hueso más fracturado carpo","enunciado":"¿Cuál es el hueso del carpo más frecuentemente fracturado?","opciones":{"A":"Pisiforme","B":"Grande","C":"Escafoides","D":"Semilunar"},"correcta":"C","exp":"El escafoides es el hueso del carpo más frecuentemente fracturado (70% de fracturas del carpo). Ocurre por caída sobre la mano en extensión. El dolor en la tabaquera anatómica es su signo clásico. Riesgo de necrosis avascular."},
            {"id":"hms_008","concepto":"acromion","enunciado":"El acromion es una estructura de:","opciones":{"A":"Clavícula","B":"Húmero","C":"Escápula","D":"Primera costilla"},"correcta":"C","exp":"El acromion es la prolongación lateral de la espina de la escápula. Forma el techo de la articulación del hombro y el arco coracoacromial junto con el ligamento coracoacromial y la apófisis coracoides."},
            {"id":"hms_009","concepto":"articulación radiocubital","enunciado":"La pronosupinación del antebrazo ocurre en las articulaciones:","opciones":{"A":"Del codo únicamente","B":"Radiocubitales proximal y distal","C":"De la muñeca únicamente","D":"Radiocarpiana y mediocarpiana"},"correcta":"B","exp":"La pronosupinación ocurre en las articulaciones radiocubitales proximal (trocoidea, en el codo) y distal (trocoidea, en la muñeca). El radio rota alrededor del cúbito, que es el eje fijo."},
            {"id":"hms_010","concepto":"fractura colles","enunciado":"La fractura de Colles es una fractura de:","opciones":{"A":"Escafoides por caída sobre mano","B":"Extremo distal del radio con desplazamiento dorsal","C":"Diáfisis del cúbito","D":"Cabeza del radio"},"correcta":"B","exp":"La fractura de Colles es una fractura del extremo distal del radio con desplazamiento dorsal del fragmento distal ('deformidad en dorso de tenedor'). Ocurre por caída sobre la mano extendida. Es la fractura más común en adultos mayores."},
        ]
    },
    "huesos_mi": {
        "nombre": "Huesos Miembro Inferior", "nivel": 1, "categoria": "Miembro Inferior",
        "preguntas": [
            {"id":"hmi_001","concepto":"fémur","enunciado":"¿Cuál es el hueso más largo del cuerpo humano?","opciones":{"A":"Tibia","B":"Fémur","C":"Húmero","D":"Peroné"},"correcta":"B","exp":"El fémur es el hueso más largo y resistente del cuerpo. Forma la articulación de la cadera (con el acetábulo) y de la rodilla (con la tibia y la rótula)."},
            {"id":"hmi_002","concepto":"trocánteres","enunciado":"El trocánter MAYOR del fémur es inserción principalmente de:","opciones":{"A":"Iliopsoas","B":"Glúteo mayor","C":"Glúteos medio y menor","D":"Cuádriceps femoral"},"correcta":"C","exp":"El trocánter mayor es la inserción de los glúteos medio y menor (abductores). El trocánter menor es la inserción del iliopsoas (flexor de cadera). El glúteo mayor se inserta en la tuberosidad glútea del fémur."},
            {"id":"hmi_003","concepto":"rótula","enunciado":"La rótula es un hueso de tipo:","opciones":{"A":"Largo","B":"Corto","C":"Sesamoideo","D":"Irregular"},"correcta":"C","exp":"La rótula es el hueso sesamoideo más grande del cuerpo. Está incluida en el tendón del cuádriceps femoral. Aumenta el brazo de palanca del cuádriceps para la extensión de la rodilla."},
            {"id":"hmi_004","concepto":"maléolos","enunciado":"El maléolo MEDIAL (interno) es una estructura de:","opciones":{"A":"Peroné","B":"Tibia","C":"Fémur","D":"Astrágalo"},"correcta":"B","exp":"El maléolo medial es la prominencia distal medial de la tibia. El maléolo lateral (externo) es la parte distal del peroné. Juntos forman la mortaja tibioperonea que abraza al astrágalo."},
            {"id":"hmi_005","concepto":"tarso","enunciado":"¿Cuántos huesos tiene el tarso?","opciones":{"A":"5","B":"6","C":"7","D":"8"},"correcta":"C","exp":"El tarso tiene 7 huesos: Calcáneo, Astrágalo, Navicular, Cuboides y 3 Cuneiformes (medial, intermedio, lateral). Nemotecnia: 'Ca-As-Na-Cu-3C'."},
            {"id":"hmi_006","concepto":"calcáneo","enunciado":"¿Cuál es el hueso más grande del tarso?","opciones":{"A":"Astrágalo","B":"Navicular","C":"Calcáneo","D":"Cuboides"},"correcta":"C","exp":"El calcáneo es el mayor del tarso y forma el talón. Es la inserción del tendón de Aquiles (tríceps sural). La fractura del calcáneo es la fractura de tarso más frecuente (caídas desde altura)."},
            {"id":"hmi_007","concepto":"astrágalo","enunciado":"¿Qué hueso del tarso articula directamente con la tibia?","opciones":{"A":"Calcáneo","B":"Navicular","C":"Astrágalo","D":"Cuboides"},"correcta":"C","exp":"El astrágalo articula con tibia y peroné (mortaja tibioperonea) formando la articulación del tobillo (articulación talocrural). Es el único hueso del tarso sin inserción muscular directa."},
            {"id":"hmi_008","concepto":"pie en total","enunciado":"¿Cuántos huesos tiene el pie en total?","opciones":{"A":"24","B":"26","C":"28","D":"30"},"correcta":"B","exp":"El pie tiene 26 huesos: 7 tarsianos + 5 metatarsianos + 14 falanges (2 en el 1er dedo y 3 en el resto). Igual que la mano (27 con el sesamoideo del pulgar)."},
            {"id":"hmi_009","concepto":"fractura cadera","enunciado":"En fracturas de cuello femoral, ¿qué arteria está en riesgo de lesión?","opciones":{"A":"Arteria femoral","B":"Arterias circunflejas femorales","C":"Arteria poplítea","D":"Arteria obturatriz"},"correcta":"B","exp":"Las arterias circunflejas femorales medial y lateral irrigan la cabeza y cuello del fémur. Su lesión en fracturas de cuello femoral puede causar necrosis avascular de la cabeza femoral. Por eso es una fractura de urgencia."},
            {"id":"hmi_010","concepto":"línea intertrocantérea","enunciado":"¿Dónde se origina el ligamento iliofemoral (ligamento de Bigelow)?","opciones":{"A":"En la espina ilíaca anterosuperior","B":"En la espina ilíaca anteroinferior y línea intertrocantérea","C":"En el trocánter mayor","D":"En el acetábulo"},"correcta":"B","exp":"El ligamento iliofemoral (de Bigelow) es el más fuerte del cuerpo. Une la espina ilíaca anteroinferior con la línea intertrocantérea. Tiene forma de Y y previene la hiperextensión de la cadera."},
        ]
    },
    "nervios_mmii": {
        "nombre": "Nervios Miembro Inferior", "nivel": 1, "categoria": "Miembro Inferior",
        "preguntas": [
            {"id":"nmi_001","concepto":"nervio ciático","enunciado":"¿De qué raíces se origina el nervio ciático?","opciones":{"A":"L2-L3-L4","B":"L3-L4-L5-S1","C":"L4-L5-S1-S2-S3","D":"L2-L3-L4-L5"},"correcta":"C","exp":"El nervio ciático (plexo sacro) se origina de L4-L5-S1-S2-S3. Es el nervio más largo y grueso del cuerpo. Sale por el foramen ciático mayor, pasa bajo el piriforme y desciende por la cara posterior del muslo."},
            {"id":"nmi_002","concepto":"nervio ciático","enunciado":"¿Dónde se divide el nervio ciático en sus dos ramas terminales?","opciones":{"A":"Glúteo mayor","B":"Canal de Hunter","C":"Fosa poplítea","D":"Foramen ciático menor"},"correcta":"C","exp":"El nervio ciático se divide en la fosa poplítea (vértice superior) en: nervio tibial (continúa hacia abajo) y nervio peroneo común (rodea la cabeza del peroné). Esta división puede ocurrir más arriba en variantes anatómicas."},
            {"id":"nmi_003","concepto":"nervio peroneo","enunciado":"La lesión del nervio peroneo común en el cuello del peroné produce:","opciones":{"A":"Pie equino (flexión plantar fija)","B":"Pie caído (steppage) por parálisis de dorsiflexores","C":"Pérdida de flexión de rodilla","D":"Parálisis de los aductores"},"correcta":"B","exp":"El nervio peroneo común rodea el cuello del peroné y es muy vulnerable. Su lesión paraliza el tibial anterior (dorsiflexión) y extensores de los dedos → 'pie caído'. El paciente levanta exageradamente la rodilla al caminar (marcha en steppage)."},
            {"id":"nmi_004","concepto":"nervio femoral","enunciado":"¿Qué inerva el nervio femoral?","opciones":{"A":"Músculos aductores del muslo","B":"Cuádriceps femoral y sensibilidad anterior del muslo","C":"Flexores del muslo","D":"Músculos de la pierna"},"correcta":"B","exp":"El nervio femoral (L2-L4) inerva: cuádriceps (extensión de rodilla), sartorio, pectíneo, y la sensibilidad de la cara anterior del muslo y parte medial de la pierna (nervio safeno). Su lesión imposibilita extender la rodilla."},
            {"id":"nmi_005","concepto":"nervio obturador","enunciado":"¿Qué músculos inerva el nervio obturador?","opciones":{"A":"Extensores del muslo","B":"Aductores del muslo","C":"Flexores de la rodilla","D":"Dorsiflexores del pie"},"correcta":"B","exp":"El nervio obturador (L2-L4) inerva los aductores del muslo: pectíneo, aductor largo, corto y mayor, grácil y obturador externo. Sale por el agujero obturador. Su lesión: dificultad para cruzar las piernas."},
            {"id":"nmi_006","concepto":"nervio tibial","enunciado":"¿Qué produce la lesión del nervio tibial?","opciones":{"A":"Pie caído","B":"Pie zambo (equinovaro) y pérdida de flexión plantar","C":"Pérdida de extensión de la rodilla","D":"Parálisis del glúteo"},"correcta":"B","exp":"El nervio tibial (L4-S3) inerva los flexores plantares (tríceps sural) y los músculos de la planta del pie. Su lesión produce pie en calcáneo (incapacidad para la flexión plantar), pérdida de la sensibilidad plantar."},
            {"id":"nmi_007","concepto":"plexo lumbar","enunciado":"¿Cuál de estos nervios NO pertenece al plexo lumbar?","opciones":{"A":"Nervio femoral","B":"Nervio obturador","C":"Nervio iliohipogástrico","D":"Nervio ciático"},"correcta":"D","exp":"El nervio ciático es la principal rama del plexo SACRO (L4-S3). El plexo lumbar (L1-L4) da: iliohipogástrico, ilioinguinal, genitofemoral, cutáneo lateral del muslo, femoral y obturador."},
            {"id":"nmi_008","concepto":"síndrome del piriforme","enunciado":"El síndrome del piriforme puede comprimir al nervio:","opciones":{"A":"Femoral","B":"Obturador","C":"Ciático","D":"Peroneo superficial"},"correcta":"C","exp":"El nervio ciático pasa bajo el músculo piriforme (o a veces a través de él). La hipertensión/contractura del piriforme puede comprimir el ciático, causando dolor similar a la ciática discal. Se alivia con estiramiento del piriforme."},
            {"id":"nmi_009","concepto":"dermatomas","enunciado":"El dermatoma del dorso del pie (excepto 1er espacio interdigital) corresponde a:","opciones":{"A":"L3","B":"L4","C":"L5","D":"S1"},"correcta":"C","exp":"L5 inerva la parte dorsal del pie y el 1er espacio interdigital (entre 1er y 2er dedo). S1 inerva el talón y el borde lateral del pie. L4 inerva la cara medial de la pierna. Importante para localizar hernias discales."},
            {"id":"nmi_010","concepto":"hernia L5-S1","enunciado":"Una hernia discal L5-S1 que comprime la raíz S1 produce:","opciones":{"A":"Pérdida de reflejo rotuliano","B":"Pérdida de reflejo aquíleo","C":"Pie caído","D":"Debilidad del cuádriceps"},"correcta":"B","exp":"La raíz S1 se evalúa con: reflejo aquíleo (se pierde), sensibilidad del talón y borde lateral del pie, y fuerza de la flexión plantar (puntillas). La raíz L4 da el reflejo rotuliano; L4-L5 da la dorsiflexión del pie."},
        ]
    },
    "rodilla": {
        "nombre": "Rodilla", "nivel": 1, "categoria": "Miembro Inferior",
        "preguntas": [
            {"id":"rod_001","concepto":"LCA","enunciado":"¿Cuál es la función principal del ligamento cruzado anterior (LCA)?","opciones":{"A":"Evitar el desplazamiento posterior de la tibia","B":"Evitar el desplazamiento anterior de la tibia sobre el fémur","C":"Evitar el valgo de rodilla","D":"Evitar la rotación externa de la tibia"},"correcta":"B","exp":"El LCA evita el desplazamiento anterior de la tibia respecto al fémur. Se tensa en extensión de rodilla. Su lesión es la más frecuente en deportes de pivote (fútbol, esquí). El cajón anterior y el test de Lachman lo evalúan."},
            {"id":"rod_002","concepto":"LCA","enunciado":"El test de Lachman valora la integridad del:","opciones":{"A":"Ligamento colateral medial","B":"Menisco medial","C":"Ligamento cruzado anterior","D":"Ligamento cruzado posterior"},"correcta":"C","exp":"El test de Lachman es el gold standard para lesión del LCA: rodilla a 20-30° de flexión, se tracciona la tibia hacia adelante. Positivo: desplazamiento anterior sin tope firme. Más sensible que el cajón anterior en agudo."},
            {"id":"rod_003","concepto":"LCP","enunciado":"La función del ligamento cruzado posterior (LCP) es:","opciones":{"A":"Evitar el desplazamiento anterior de la tibia","B":"Evitar el desplazamiento posterior de la tibia sobre el fémur","C":"Estabilizar el compartimento medial","D":"Guiar la rotación interna en extensión"},"correcta":"B","exp":"El LCP es el más fuerte de los dos cruzados. Evita el desplazamiento POSTERIOR de la tibia. Se lesiona por golpe en la tibia proximal con rodilla en flexión (accidentes de coche, 'dashboard injury'). El cajón posterior lo evalúa."},
            {"id":"rod_004","concepto":"meniscos","enunciado":"¿Cuál de los dos meniscos se lesiona con mayor frecuencia?","opciones":{"A":"Menisco lateral","B":"Menisco medial","C":"Ambos por igual","D":"Depende de la edad"},"correcta":"B","exp":"El menisco medial se lesiona más (75%) porque está firmemente unido al ligamento colateral medial y la cápsula articular, lo que lo hace menos móvil. El menisco lateral es más redondo y móvil. Lesión clásica: rotación con pie fijo."},
            {"id":"rod_005","concepto":"tríada maldita","enunciado":"La 'tríada maldita' de O'Donoghue incluye lesión de:","opciones":{"A":"LCA + LCP + menisco lateral","B":"LCA + LCM + menisco medial","C":"LCP + LCL + menisco lateral","D":"LCA + LCL + menisco medial"},"correcta":"B","exp":"La tríada desgraciada (O'Donoghue): LCA + LCM + menisco medial. Ocurre por valgismo forzado con rotación. El LCM y el menisco medial están unidos, por lo que una lesión del LCM frecuentemente arrastra al menisco medial."},
            {"id":"rod_006","concepto":"ligamento colateral","enunciado":"¿Qué ligamento de la rodilla previene el valgo?","opciones":{"A":"Ligamento cruzado anterior","B":"Ligamento colateral lateral (LCL)","C":"Ligamento colateral medial (LCM)","D":"Ligamento cruzado posterior"},"correcta":"C","exp":"El LCM (medial) resiste el estrés en valgo (rodilla se abre hacia afuera). El LCL (lateral) resiste el estrés en varo (rodilla se abre hacia adentro). Lesión del LCM: dolor medial, inestabilidad valgo."},
            {"id":"rod_007","concepto":"tendón rotuliano","enunciado":"El tendón rotuliano une:","opciones":{"A":"Cuádriceps con la rótula","B":"Rótula con la tuberosidad tibial anterior","C":"Fémur con la tibia","D":"Ísquion con el fémur"},"correcta":"B","exp":"El tendón rotuliano (o ligamento rotuliano) va desde el polo inferior de la rótula hasta la tuberosidad tibial anterior. El tendón del cuádriceps va desde el cuádriceps hasta el polo superior de la rótula. Juntos forman el aparato extensor de la rodilla."},
            {"id":"rod_008","concepto":"cajón posterior","enunciado":"El signo del cajón posterior positivo indica lesión del:","opciones":{"A":"LCA","B":"LCM","C":"LCP","D":"Menisco medial"},"correcta":"C","exp":"Cajón posterior: con la rodilla a 90° de flexión, se empuja la tibia hacia atrás. Si se desplaza excesivamente hacia atrás = LCP roto. El signo del cuadro o sagging sign (la tibia 'cae' hacia atrás) también indica lesión del LCP."},
            {"id":"rod_009","concepto":"bursas rodilla","enunciado":"La bursitis más frecuente de la rodilla en trabajadores que se arrodillan es:","opciones":{"A":"Bursa semimembranosa","B":"Bursa infrarrotuliana profunda","C":"Bursa prerrotuliana","D":"Quiste de Baker"},"correcta":"C","exp":"La bursitis prerrotuliana ('rodilla del ama de casa') afecta a personas que se arrodillan mucho. Se manifiesta como una colección redondeada frente a la rótula. El quiste de Baker (poplíteo) es una bursitis posterior por derrame articular crónico."},
            {"id":"rod_010","concepto":"anatomía","enunciado":"¿Cuántos compartimentos tiene la articulación de la rodilla?","opciones":{"A":"1 (un solo compartimento)","B":"2 (medial y lateral)","C":"3 (medial, lateral y patelofemoral)","D":"4 compartimentos"},"correcta":"C","exp":"La rodilla tiene 3 compartimentos: medial (fémur medial + tibia medial), lateral (fémur lateral + tibia lateral) y patelofemoral (rótula + tróclea femoral). La artrosis puede afectar selectivamente cada compartimento."},
        ]
    },
    "huesos_craneo": {
        "nombre": "Huesos del Cráneo", "nivel": 1, "categoria": "Cráneo",
        "preguntas": [
            {"id":"hc_001","concepto":"neurocráneo","enunciado":"¿Cuántos huesos forman el neurocráneo?","opciones":{"A":"6","B":"8","C":"14","D":"22"},"correcta":"B","exp":"El neurocráneo (caja craneana) tiene 8 huesos: 1 frontal, 2 parietales, 1 occipital, 2 temporales, 1 esfenoides y 1 etmoides. El viscerocráneo (cara) tiene 14 huesos."},
            {"id":"hc_002","concepto":"neurocráneo","enunciado":"¿Cuál de estos huesos NO forma parte del neurocráneo?","opciones":{"A":"Esfenoides","B":"Etmoides","C":"Vómer","D":"Occipital"},"correcta":"C","exp":"El vómer es un hueso del viscerocráneo (forma parte del tabique nasal). Los 8 huesos del neurocráneo son: frontal, 2 parietales, occipital, 2 temporales, esfenoides y etmoides."},
            {"id":"hc_003","concepto":"silla turca","enunciado":"La silla turca, que aloja la hipófisis, se encuentra en el hueso:","opciones":{"A":"Temporal","B":"Frontal","C":"Esfenoides","D":"Etmoides"},"correcta":"C","exp":"La silla turca (fosa hipofisaria) es una depresión en el cuerpo del esfenoides. Aloja la hipófisis (glándula pituitaria). Los adenomas hipofisarios pueden comprimir el quiasma óptico superior → hemianopsia bitemporal."},
            {"id":"hc_004","concepto":"temporal","enunciado":"¿Qué estructura importante se encuentra en el hueso temporal?","opciones":{"A":"Silla turca","B":"Foramen magno","C":"Proceso mastoideo y conducto auditivo interno","D":"Crista galli"},"correcta":"C","exp":"El temporal contiene: proceso mastoideo (neumatizado), conducto auditivo externo e interno, cóclea, canales semicirculares, y aloja el oído medio. La mastoiditis es la infección de las celdillas del proceso mastoideo."},
            {"id":"hc_005","concepto":"ptérion","enunciado":"El ptérion es la unión de los huesos:","opciones":{"A":"Frontal + Occipital + Temporal","B":"Frontal + Parietal + Temporal + Esfenoides","C":"Parietal + Occipital + Temporal","D":"Frontal + Parietal + Occipital"},"correcta":"B","exp":"El ptérion es la unión en H de frontal + parietal + temporal + esfenoides en la sien. Es el punto más delgado del cráneo. Bajo el ptérion discurre la arteria meníngea media → hematoma epidural con fractura aquí."},
            {"id":"hc_006","concepto":"foramen magno","enunciado":"¿En qué hueso se encuentra el foramen magno?","opciones":{"A":"Temporal","B":"Esfenoides","C":"Parietal","D":"Occipital"},"correcta":"D","exp":"El foramen magno (agujero occipital) está en el hueso occipital. Por él pasan: el tronco del encéfalo (bulbo-médula), arterias vertebrales, arterias espinales anterior y posterior, y raíces del nervio espinal accesorio (XI)."},
            {"id":"hc_007","concepto":"sutura lambdoidea","enunciado":"La sutura lambdoidea une:","opciones":{"A":"Frontal con parietales","B":"Los dos parietales entre sí","C":"Parietales con occipital","D":"Parietales con temporales"},"correcta":"C","exp":"Suturas principales: Coronal (frontal+parietales), Sagital (entre parietales), Lambdoidea (parietales+occipital), Escamosa (temporal+parietal). Bregma = sagital+coronal. Lambda = sagital+lambdoidea."},
            {"id":"hc_008","concepto":"crista galli","enunciado":"¿En qué hueso se encuentra la crista galli?","opciones":{"A":"Frontal","B":"Etmoides","C":"Esfenoides","D":"Vómer"},"correcta":"B","exp":"La crista galli es la proyección superior del etmoides en la fosa craneal anterior. Es la inserción de la hoz del cerebro (duramadre). La lámina cribosa del etmoides, a sus lados, transmite los nervios olfativos (I par craneal)."},
            {"id":"hc_009","concepto":"techo órbita","enunciado":"¿Qué hueso forma principalmente el techo de la órbita?","opciones":{"A":"Cigomático","B":"Esfenoides","C":"Frontal","D":"Etmoides"},"correcta":"C","exp":"El techo de la órbita está formado principalmente por la porción orbitaria del frontal (y una pequeña parte del ala menor del esfenoides). El suelo de la órbita es el maxilar superior (frágil, fractura por contragolpe)."},
            {"id":"hc_010","concepto":"bregma","enunciado":"¿Cómo se denomina el punto donde se unen las suturas sagital y coronal?","opciones":{"A":"Lambda","B":"Pterion","C":"Bregma","D":"Nasion"},"correcta":"C","exp":"Bregma = unión de la sutura sagital y coronal (frontera entre frontal y parietales). En los recién nacidos, aquí se encuentra la fontanela anterior (bregmática), la más grande. Cierra a los 18-24 meses de vida."},
        ]
    },
    "craneo_foramenes": {
        "nombre": "Forámenes del Cráneo", "nivel": 1, "categoria": "Cráneo",
        "preguntas": [
            {"id":"cf_001","concepto":"nervio óptico","enunciado":"El nervio óptico (II par craneal) sale del cráneo por:","opciones":{"A":"Fisura orbitaria superior","B":"Fisura orbitaria inferior","C":"Canal óptico","D":"Foramen rotundo"},"correcta":"C","exp":"El nervio óptico (II PC) pasa por el canal óptico junto con la arteria oftálmica (rama de la carótida interna). El canal óptico está en el ala menor del esfenoides."},
            {"id":"cf_002","concepto":"fisura orbitaria","enunciado":"¿Qué nervios craneales pasan por la fisura orbitaria SUPERIOR?","opciones":{"A":"II, III, IV","B":"III, IV, V1 y VI","C":"V2, VI, VII","D":"II, VI, VII"},"correcta":"B","exp":"Fisura orbitaria superior: III (oculomotor), IV (troclear), V1 (oftálmico), VI (abducens) y la vena oftálmica superior. El síndrome de la fisura orbitaria superior paraliza todos los movimientos oculares más la sensibilidad corneal."},
            {"id":"cf_003","concepto":"foramen oval","enunciado":"Por el foramen oval sale el nervio:","opciones":{"A":"V1 (oftálmico)","B":"V2 (maxilar)","C":"V3 (mandibular)","D":"VII (facial)"},"correcta":"C","exp":"Foramen oval: V3 (nervio mandibular, rama del trigémino). Está en el ala mayor del esfenoides. Regla: V1 por fisura orbitaria superior, V2 por foramen redondo, V3 por foramen oval (creciente: de arriba a abajo)."},
            {"id":"cf_004","concepto":"foramen redondo","enunciado":"¿Qué nervio sale por el foramen redondo?","opciones":{"A":"V1","B":"V2","C":"V3","D":"IX"},"correcta":"B","exp":"El foramen redondo transmite el nervio maxilar (V2), rama del trigémino. Está en el ala mayor del esfenoides, en la fosa media. V2 pasa al canal pterigopalatino y da sensibilidad a mejilla, labio superior, encía superior."},
            {"id":"cf_005","concepto":"foramen yugular","enunciado":"Por el foramen yugular pasan los pares craneales:","opciones":{"A":"VII, VIII","B":"IX, X, XI","C":"X, XI, XII","D":"IX, X, XI y XII"},"correcta":"B","exp":"Foramen yugular: IX (glosofaríngeo), X (vago), XI (accesorio espinal) y el seno venoso sigmoideo (que se convierte en vena yugular interna). El XII sale por el canal hipogloso (diferente foramen)."},
            {"id":"cf_006","concepto":"foramen estilomastoideo","enunciado":"El nervio facial (VII par) sale del cráneo por:","opciones":{"A":"Canal auditivo interno","B":"Foramen yugular","C":"Agujero estilomastoideo","D":"Fisura petroescamosa"},"correcta":"C","exp":"El VII sale por el agujero estilomastoideo (entre apófisis estiloides y mastoides). Antes de salir, da: nervio petroso mayor (glándulas lagrimales), nervio del músculo del estribo, y cuerda del tímpano (gusto 2/3 anteriores lengua)."},
            {"id":"cf_007","concepto":"meato acústico interno","enunciado":"¿Qué nervios pasan por el meato acústico interno?","opciones":{"A":"V y VI","B":"VII y VIII","C":"IX y X","D":"Solo el VIII"},"correcta":"B","exp":"Por el meato acústico interno (en la cara posterior del peñasco del temporal) pasan: VII (facial) y VIII (vestibulococlear). Los schwannomas vestibulares (neurinomas del acústico) se localizan aquí y comprimen ambos nervios."},
            {"id":"cf_008","concepto":"foramen espinoso","enunciado":"¿Qué estructura pasa por el foramen espinoso?","opciones":{"A":"Arteria carótida interna","B":"Arteria meníngea media","C":"Nervio facial","D":"Seno cavernoso"},"correcta":"B","exp":"El foramen espinoso (ala mayor del esfenoides) transmite la arteria meníngea media, rama de la maxilar interna. Esta arteria discurre por el ptérion y puede lesionarse con fracturas temporales → hematoma epidural agudo."},
            {"id":"cf_009","concepto":"canal hipogloso","enunciado":"El nervio hipogloso (XII par) sale por:","opciones":{"A":"Foramen magno","B":"Foramen yugular","C":"Canal hipogloso","D":"Agujero estilomastoideo"},"correcta":"C","exp":"El nervio hipogloso sale por el canal hipogloso (condíleo anterior), un canal en el occipital lateral al foramen magno. Inerva todos los músculos intrínsecos y extrínsecos de la lengua (excepto el palatogloso)."},
            {"id":"cf_010","concepto":"fosas craneales","enunciado":"¿En qué fosa craneal se aloja el lóbulo frontal?","opciones":{"A":"Fosa media","B":"Fosa posterior","C":"Fosa anterior","D":"No está en ninguna fosa"},"correcta":"C","exp":"Fosa craneal anterior: lóbulos frontales. Fosa media (central): lóbulos temporales + hipófisis (silla turca). Fosa posterior: cerebelo + tronco del encéfalo. La fosa posterior está delimitada por la tienda del cerebelo (tentorio)."},
        ]
    },
    "nervios_craneales": {
        "nombre": "Nervios Craneales", "nivel": 1, "categoria": "Cráneo",
        "preguntas": [
            {"id":"nc_001","concepto":"número y nombres","enunciado":"¿Cuántos pares de nervios craneales hay?","opciones":{"A":"10","B":"11","C":"12","D":"13"},"correcta":"C","exp":"Hay 12 pares craneales (I-XII). Nemotecnia para recordarlos en orden: 'On Old Olympus Towering Tops, A Finnish Veteran's Gentle Voyage Acquires Humor' (O, O, O, T, T, A, F, V, G, V, A, H)."},
            {"id":"nc_002","concepto":"nervio vago","enunciado":"¿Cuál es el nervio craneal más largo y de mayor distribución?","opciones":{"A":"V (trigémino)","B":"VII (facial)","C":"X (vago)","D":"XI (accesorio)"},"correcta":"C","exp":"El nervio vago (X par) es el más extenso: sale del cráneo por el foramen yugular y desciende hasta el abdomen. Inerva vísceras torácicas y abdominales (parasimpático). Es el nervio del sistema nervioso autónomo por excelencia."},
            {"id":"nc_003","concepto":"músculos masticación","enunciado":"¿Qué nervio craneal inerva los músculos de la masticación?","opciones":{"A":"V1 (nervio oftálmico)","B":"V2 (nervio maxilar)","C":"V3 (nervio mandibular)","D":"VII (nervio facial)"},"correcta":"C","exp":"V3 (mandibular) es la única rama motora del trigémino. Inerva los músculos de la masticación: masetero, temporales, pterigoideos medial y lateral, más tensor del tímpano y tensor del velo del paladar."},
            {"id":"nc_004","concepto":"músculos expresión","enunciado":"Los músculos de la expresión facial están inervados por:","opciones":{"A":"Nervio trigémino (V)","B":"Nervio facial (VII)","C":"Nervio glosofaríngeo (IX)","D":"Nervio hipogloso (XII)"},"correcta":"B","exp":"El nervio facial (VII) inerva todos los músculos mímicos (expresión facial). Sus ramas periféricas: temporal, cigomática, bucal, mandibular marginal, cervical. Lesión periférica = parálisis de Bell (toda la hemicara)."},
            {"id":"nc_005","concepto":"parálisis de Bell","enunciado":"En la parálisis de Bell (parálisis facial periférica), ¿qué ocurre con la frente?","opciones":{"A":"Solo se afecta la parte inferior de la cara","B":"Se afecta toda la hemicara incluyendo la frente","C":"La frente no se afecta porque tiene inervación bilateral","D":"La frente solo se afecta en lesiones centrales"},"correcta":"B","exp":"La parálisis periférica del VII afecta TODA la hemicara (incluyendo la frente). En la parálisis central (ictus), la frente se salva porque recibe inervación bilateral cortical. Esta distinción es clave para diferenciar lesión central de periférica."},
            {"id":"nc_006","concepto":"nervio troclear","enunciado":"¿Cuál es el único nervio craneal que sale por la cara POSTERIOR del tronco del encéfalo?","opciones":{"A":"III (oculomotor)","B":"IV (troclear)","C":"VI (abducens)","D":"VII (facial)"},"correcta":"B","exp":"El nervio troclear (IV) es único porque: 1) sale por la cara posterior del mesencéfalo, 2) se decusa (cruza) antes de salir, 3) tiene el trayecto intracraneal más largo, 4) tiene el menor número de fibras de todos los PC motores."},
            {"id":"nc_007","concepto":"músculo oblicuo superior","enunciado":"El nervio troclear (IV) inerva:","opciones":{"A":"Recto superior","B":"Oblicuo inferior","C":"Oblicuo superior","D":"Recto medial"},"correcta":"C","exp":"IV = Oblicuo Superior (TROCLEAR → Trochlea → rota hacia abajo y afuera). El III inerva el resto de músculos extromotores (recto superior, inferior, medial, oblicuo inferior y elevador del párpado). El VI inerva solo el recto lateral."},
            {"id":"nc_008","concepto":"nervio abducens","enunciado":"La parálisis del nervio abducens (VI par craneal) produce:","opciones":{"A":"Ptosis palpebral y midriasis","B":"Estrabismo convergente (esotropía)","C":"Estrabismo divergente (exotropía)","D":"Diplopia vertical"},"correcta":"B","exp":"El VI inerva el recto lateral (abductor del ojo). Su parálisis → el ojo queda en aducción por el recto medial sin oposición → estrabismo convergente (esotropía). Diplopía horizontal. El VI tiene el trayecto más largo dentro del cráneo."},
            {"id":"nc_009","concepto":"nervio accesorio","enunciado":"¿Qué músculos inerva el nervio accesorio (XI par craneal)?","opciones":{"A":"Músculos de la lengua","B":"Músculos de la faringe","C":"Esternocleidomastoideo y trapecio","D":"Músculos de la laringe"},"correcta":"C","exp":"El nervio accesorio (XI) inerva el esternocleidomastoideo (rotación de la cabeza) y el trapecio (elevación del hombro). Su lesión → incapacidad de encoger el hombro y debilidad para rotar la cabeza hacia el lado opuesto."},
            {"id":"nc_010","concepto":"nervio hipogloso","enunciado":"La lesión del nervio hipogloso (XII) produce:","opciones":{"A":"Disfagia y disfonía","B":"La lengua desvía hacia el lado SANO","C":"La lengua desvía hacia el lado LESIONADO","D":"Pérdida del gusto en los 2/3 anteriores de la lengua"},"correcta":"C","exp":"La lesión del XII produce: atrofia y fasciculaciones de la lengua ipsilateral, y desviación hacia el lado LESIONADO al protruir (el lado sano empuja). La lesión de la VÍA CORTICAL (primera motoneurona) desvía la lengua hacia el lado contrario a la lesión."},
        ]
    },
    "columna": {
        "nombre": "Columna Vertebral", "nivel": 1, "categoria": "Vértebras",
        "preguntas": [
            {"id":"col_001","concepto":"número vértebras","enunciado":"¿Cuántas vértebras cervicales tiene la columna vertebral?","opciones":{"A":"5","B":"6","C":"7","D":"8"},"correcta":"C","exp":"Columna vertebral: 7 cervicales (C1-C7) + 12 torácicas (T1-T12) + 5 lumbares (L1-L5) + 5 sacras fusionadas (sacro) + 3-4 coccígeas. Total: 33-34 vértebras. Los nervios espinales son 31 pares."},
            {"id":"col_002","concepto":"curvaturas","enunciado":"¿Cuál de las siguientes curvaturas de la columna es una CIFOSIS?","opciones":{"A":"Cervical","B":"Lumbar","C":"Torácica","D":"Sacra desde el punto de vista de curvatura fisiológica principal"},"correcta":"C","exp":"Cifosis = convexidad posterior (cóncava anteriormente): torácica y sacrococcígea (son las curvaturas primarias, presentes desde el feto). Lordosis = convexidad anterior (cóncava posteriormente): cervical y lumbar (secundarias, se desarrollan al erguirse)."},
            {"id":"col_003","concepto":"curvaturas","enunciado":"¿Qué tipo de curvatura es la lordosis lumbar?","opciones":{"A":"Curvatura primaria, cóncava anteriormente","B":"Curvatura secundaria, cóncava posteriormente (convexa anteriormente)","C":"Curvatura primaria, convexa posteriormente","D":"No existe lordosis lumbar fisiológica"},"correcta":"B","exp":"La lordosis lumbar es una curvatura secundaria (se desarrolla cuando el niño comienza a caminar). Es cóncava posterior = convexa anterior. Se exagera en el embarazo. La hiperlordosis lumbar puede causar lumbalgia crónica."},
            {"id":"col_004","concepto":"médula espinal","enunciado":"¿En qué nivel termina la médula espinal en el adulto?","opciones":{"A":"T12","B":"L1-L2","C":"L3-L4","D":"S1"},"correcta":"B","exp":"La médula espinal en adultos termina entre L1 y L2 (cono medular). Por debajo continúan las raíces nerviosas formando la cola de caballo. En recién nacidos termina más abajo (L3). Por eso, la punción lumbar se hace entre L3-L4 o L4-L5."},
            {"id":"col_005","concepto":"vértebra prominente","enunciado":"¿Cuál es la vértebra prominente y cómo se identifica?","opciones":{"A":"C6, por su apófisis espinosa larga no bifurcada","B":"C7, por ser la más palpable en la nuca con apófisis espinosa larga","C":"T1, primera vértebra torácica","D":"C5, la más móvil de la columna cervical"},"correcta":"B","exp":"La vértebra prominente es C7 (vertebra prominens): tiene la apófisis espinosa más larga y es la más palpable en la nuca. C2-C6 tienen apófisis espinosas bífidas. C7 y T1 no son bífidas. Es el punto de referencia para contar las vértebras."},
            {"id":"col_006","concepto":"nervios espinales","enunciado":"¿Cuántos pares de nervios espinales hay en total?","opciones":{"A":"29","B":"31","C":"33","D":"12"},"correcta":"B","exp":"31 pares de nervios espinales: 8 cervicales (C1-C8, aunque solo hay 7 vértebras cervicales), 12 torácicos, 5 lumbares, 5 sacros y 1 coccígeo. Hay 8 pares cervicales porque C1 sale sobre C1 y C8 sale bajo C7."},
            {"id":"col_007","concepto":"cola de caballo","enunciado":"La 'cola de caballo' está formada por:","opciones":{"A":"La médula espinal lumbar y sacra","B":"Las raíces nerviosas L2-S5 que descienden en el canal raquídeo","C":"El filum terminale únicamente","D":"Los nervios simpáticos lumbares"},"correcta":"B","exp":"La cola de caballo (cauda equina) son las raíces nerviosas de L2 a S5 que descienden por el canal raquídeo tras terminar la médula (L1-L2). El síndrome de la cola de caballo: anestesia en silla de montar, disfunción esfinteriana, paraparesia."},
            {"id":"col_008","concepto":"canal medular","enunciado":"¿Qué estructura llena el canal medular por debajo del cono medular?","opciones":{"A":"La médula espinal","B":"El líquido cefalorraquídeo y las raíces nerviosas (cauda equina)","C":"La duramadre sola","D":"El filum terminale solo"},"correcta":"B","exp":"Por debajo de L1-L2: el canal raquídeo contiene LCR, la cauda equina (raíces L2-S5) y el filum terminale (L2 → cóccix). El espacio subaracnoideo lumbar es ideal para la punción lumbar (L3-L4 o L4-L5), con poco riesgo de lesionar la médula."},
            {"id":"col_009","concepto":"articulación atlantooccipital","enunciado":"La articulación atlantooccipital permite principalmente:","opciones":{"A":"Rotación de la cabeza (decir NO)","B":"Flexoextensión de la cabeza (decir SÍ)","C":"Inclinación lateral de la cabeza","D":"Todos los movimientos por igual"},"correcta":"B","exp":"La articulación atlantooccipital (C0-C1) permite flexoextensión (asentir con la cabeza = 'decir SÍ'). La atlantoaxial (C1-C2) permite la rotación (negar con la cabeza = 'decir NO'). Ambas son las más móviles de la columna cervical."},
            {"id":"col_010","concepto":"ángulo de Louis","enunciado":"El ángulo de Louis (ángulo esternal) se proyecta a nivel de:","opciones":{"A":"T2-T3","B":"T4-T5","C":"T6-T7","D":"T1-T2"},"correcta":"B","exp":"El ángulo de Louis (unión manubrioesternal) se proyecta a nivel de T4-T5, segunda articulación condroesternal, bifurcación traqueal (carina), y el inicio del arco aórtico. Es un hito anatómico clave en exploración torácica."},
        ]
    },
    "atlas_axis": {
        "nombre": "Atlas y Axis (C1-C2)", "nivel": 1, "categoria": "Vértebras",
        "preguntas": [
            {"id":"aa_001","concepto":"atlas anatomía","enunciado":"¿Qué característica anatómica distingue al atlas (C1) de todas las demás vértebras?","opciones":{"A":"Tiene apófisis espinosa muy larga","B":"No tiene cuerpo vertebral","C":"Tiene agujero transverso doble","D":"Tiene solo un pedículo"},"correcta":"B","exp":"El atlas (C1) carece de cuerpo vertebral. Tiene dos masas laterales unidas por los arcos anterior y posterior. El eje (C2) tiene la apófisis odontoides que ocupa el lugar del cuerpo del atlas (filogénicamente, la odontoides es el cuerpo del C1 que se fusionó al C2)."},
            {"id":"aa_002","concepto":"apófisis odontoides","enunciado":"La apófisis odontoides (diente) es una estructura del:","opciones":{"A":"Atlas (C1)","B":"Axis (C2)","C":"C3","D":"Occipital"},"correcta":"B","exp":"La apófisis odontoides es una proyección vertical del axis (C2) que se articula con la faceta articular del arco anterior del atlas. Funciona como pivote para la rotación de la cabeza. Su fractura es una emergencia (puede comprimir el bulbo)."},
            {"id":"aa_003","concepto":"movimientos","enunciado":"El movimiento de asentir con la cabeza ('decir SÍ') ocurre en la articulación:","opciones":{"A":"Atlantoaxial (C1-C2)","B":"Atlantooccipital (C0-C1)","C":"C2-C3","D":"Intervertebral cervical en general"},"correcta":"B","exp":"Atlantooccipital (C0-C1): flexoextensión = 'decir SÍ' (50% de la flexoextensión cervical). Atlantoaxial (C1-C2): rotación = 'decir NO' (50% de la rotación cervical). Ambas articulaciones carecen de discos intervertebrales."},
            {"id":"aa_004","concepto":"movimientos","enunciado":"El 50% de la rotación cervical total ocurre en la articulación:","opciones":{"A":"Atlantooccipital (C0-C1)","B":"Atlantoaxial (C1-C2)","C":"C2-C3","D":"C4-C5"},"correcta":"B","exp":"La articulación atlantoaxial (C1-C2) permite ~50° de rotación a cada lado (total ~100°), que es el 50% de toda la rotación cervical. Es una articulación trocoidea (en pivote). El ligamento transverso del atlas retiene la odontoides."},
            {"id":"aa_005","concepto":"ligamento transverso","enunciado":"¿Qué ligamento impide que la apófisis odontoides comprima la médula espinal?","opciones":{"A":"Ligamento longitudinal anterior","B":"Ligamento transverso del atlas","C":"Ligamento amarillo","D":"Ligamento nucal"},"correcta":"B","exp":"El ligamento transverso del atlas es el más importante de la articulación atlantoaxial. Une las dos masas laterales del atlas por detrás de la odontoides. Su rotura (trauma o artritis reumatoide) permite la subluxación anterior del atlas → riesgo de compresión medular."},
            {"id":"aa_006","concepto":"arteria vertebral","enunciado":"Las arterias vertebrales ascienden por la columna cervical pasando por:","opciones":{"A":"El canal medular","B":"Los forámenes transversos (agujeros transversos) de C1-C6","C":"Los espacios intervertebrales","D":"Los pedículos vertebrales"},"correcta":"B","exp":"Las arterias vertebrales (ramas de la subclavia) ascienden por los forámenes transversos de C6 hasta C1, luego pasan por el arco posterior del atlas y entran al cráneo por el foramen magno. Se unen para formar la arteria basilar."},
            {"id":"aa_007","concepto":"fractura odontoides","enunciado":"La fractura del tipo II de Anderson-D'Alonzo de la apófisis odontoides se localiza en:","opciones":{"A":"Punta de la odontoides","B":"Base de la odontoides (unión con el cuerpo del axis)","C":"Cuerpo del axis","D":"Arco posterior del atlas"},"correcta":"B","exp":"Fracturas de odontoides: Tipo I (punta, estable), Tipo II (base, la más frecuente y menos estable, alta tasa de pseudoartrosis), Tipo III (cuerpo del axis, buena consolidación). La Tipo II es la más importante clínicamente."},
            {"id":"aa_008","concepto":"fractura jefferson","enusiado":"La fractura de Jefferson es una fractura de:","opciones":{"A":"Apófisis odontoides del axis","B":"Arco posterior del atlas por compresión axial","C":"Masa lateral del atlas con rotura del ligamento transverso","D":"Cuerpo del C3"},"enunciado":"La fractura de Jefferson es una fractura de:","opciones":{"A":"Apófisis odontoides del axis","B":"Arco posterior del atlas por compresión axial","C":"Estallido del atlas (C1) por carga axial","D":"Cuerpo del C3"},"correcta":"C","exp":"La fractura de Jefferson es una fractura en estallido del atlas (C1) por compresión axial (carga sobre la cabeza, p.ej. zambullida). Las masas laterales se desplazan hacia afuera. En la radiografía AP transoral se ve el desplazamiento lateral bilateral de las masas del atlas."},
            {"id":"aa_009","concepto":"fractura del ahorcado","enunciado":"La fractura del ahorcado (de Hangman) afecta a:","opciones":{"A":"Cuerpo del C1","B":"Apófisis odontoides del C2","C":"Pedículos bilaterales del axis (C2)","D":"Arco anterior del C1"},"correcta":"C","exp":"La fractura del ahorcado (Hangman's fracture) es la fractura bilateral de los pedículos/istmos del axis (C2) por hiperextensión + distracción. A pesar de la inestabilidad, paradójicamente suele haber poca lesión neurológica porque el canal se amplía."},
            {"id":"aa_010","concepto":"fontanelas","enunciado":"El atlas se articula superiormente con los cóndilos del hueso:","opciones":{"A":"Parietal","B":"Temporal","C":"Esfenoides","D":"Occipital"},"correcta":"D","exp":"Las masas laterales del atlas se articulan con los cóndilos del occipital formando la articulación atlantooccipital (dos articulaciones condíleas). Esta articulación permite la flexoextensión (asentir). El foramen magno del occipital es adyacente."},
        ]
    },
    "carpo_tarso": {
        "nombre": "Carpo y Tarso", "nivel": 2, "categoria": "Miembro Superior / Inferior",
        "preguntas": [
            {"id":"ct_001","concepto":"carpo proximal","enunciado":"De radial a cubital, ¿cuál es el orden correcto de la fila proximal del carpo?","opciones":{"A":"Pisiforme - Piramidal - Semilunar - Escafoides","B":"Escafoides - Semilunar - Piramidal - Pisiforme","C":"Trapecio - Trapezoide - Grande - Ganchoso","D":"Escafoides - Piramidal - Semilunar - Pisiforme"},"correcta":"B","exp":"Fila proximal (radio→cúbito): Escafoides - Semilunar - Piramidal - Pisiforme. El pisiforme es un hueso sesamoideo incluido en el tendón del flexor cubital del carpo. Nemotecnia: 'El Señor Poco Puede'."},
            {"id":"ct_002","concepto":"carpo distal","enunciado":"¿Con qué hueso del carpo articula el primer metacarpiano (pulgar)?","opciones":{"A":"Escafoides","B":"Grande","C":"Trapecio","D":"Trapezoide"},"correcta":"C","exp":"El trapecio articula con el primer metacarpiano en la articulación carpometacarpiana del pulgar (articulación en silla de montar = sellar). Esta articulación permite los movimientos de oposición del pulgar."},
            {"id":"ct_003","concepto":"hueso fracturado","enunciado":"Tras una caída sobre la mano extendida, el paciente refiere dolor en la tabaquera anatómica. ¿Qué fractura sospechas?","opciones":{"A":"Fractura de Colles del radio","B":"Fractura del escafoides","C":"Fractura del pisiforme","D":"Fractura del ganchoso"},"correcta":"B","exp":"El dolor en la tabaquera anatómica (entre los tendones del abductor largo y extensor corto del pulgar medialmente, y el extensor largo del pulgar lateralmente) es el signo clásico de la fractura de escafoides. Puede no verse en la Rx inicial."},
            {"id":"ct_004","concepto":"tarso","enunciado":"¿Cuántos huesos forman el tarso?","opciones":{"A":"5","B":"6","C":"7","D":"8"},"correcta":"C","exp":"Tarso: 7 huesos = Calcáneo + Astrágalo + Navicular + Cuboides + 3 Cuneiformes (medial, intermedio, lateral). El calcáneo es el más grande. El astrágalo articula con la tibia."},
            {"id":"ct_005","concepto":"huesos tarso","enunciado":"¿Qué hueso del tarso se encuentra entre el astrágalo y los cuneiformes?","opciones":{"A":"Cuboides","B":"Calcáneo","C":"Navicular","D":"Cuneiforme lateral"},"correcta":"C","exp":"El navicular (escafoides del tarso) se sitúa entre el astrágalo proximalmente y los 3 cuneiformes distalmente. La enfermedad de Köhler es la necrosis avascular del navicular en niños."},
            {"id":"ct_006","concepto":"necrosis avascular","enunciado":"La necrosis avascular del escafoides carpiano se debe a:","opciones":{"A":"La infección del hueso","B":"La irrigación retrógrada del escafoides (polo proximal poco vascularizado)","C":"La inestabilidad del carpo","D":"La compresión del nervio mediano"},"correcta":"B","exp":"El escafoides tiene irrigación distal-a-proximal: los vasos entran por el polo distal y el proximal queda con circulación terminal. Una fractura en la cintura del escafoides compromete el aporte al polo proximal → necrosis avascular. Por eso las fracturas de escafoides requieren tratamiento cuidadoso."},
            {"id":"ct_007","concepto":"articulación","enunciado":"La articulación de Chopart (mediotarsiana) une:","opciones":{"A":"Calcáneo-cuboides y astrágalo-navicular","B":"Navicular y los tres cuneiformes","C":"Tarso y metatarso","D":"Tibia-peroné y astrágalo"},"correcta":"A","exp":"La articulación de Chopart (mediotarsiana) está formada por: articulación calcáneo-cuboidea + articulación astrágalonavicular. Es la línea de amputación media del pie. La articulación de Lisfranc es la tarsometatarsiana."},
        ]
    },
    "musculos_ms": {
        "nombre": "Músculos Miembro Superior", "nivel": 2, "categoria": "Miembro Superior",
        "preguntas": [
            {"id":"mms_001","concepto":"bíceps","enunciado":"El bíceps braquial realiza principalmente:","opciones":{"A":"Extensión del codo y pronación","B":"Flexión del codo y supinación del antebrazo","C":"Solo flexión del codo","D":"Abducción del hombro"},"correcta":"B","exp":"El bíceps braquial: flexión del codo (especialmente con antebrazo supinado) Y supinación del antebrazo. Es más potente como supinador que como flexor. Inervado por el nervio musculocutáneo (C5-C6)."},
            {"id":"mms_002","concepto":"tríceps","enunciado":"¿Qué músculo es el principal extensor del codo?","opciones":{"A":"Bíceps braquial","B":"Braquial anterior","C":"Tríceps braquial","D":"Braquiorradial"},"correcta":"C","exp":"El tríceps braquial (tres cabezas: larga, medial y lateral) es el principal extensor del codo. Inervado por el nervio radial. Su reflejo osteotendinoso (ROT del tríceps) evalúa C7. Se inserta en el olécranon."},
            {"id":"mms_003","concepto":"pronación","enunciado":"El músculo pronador redondo está inervado por:","opciones":{"A":"Nervio radial","B":"Nervio cubital","C":"Nervio mediano","D":"Nervio musculocutáneo"},"correcta":"C","exp":"El pronador redondo (y el pronador cuadrado) están inervados por el nervio mediano. El síndrome del pronador redondo comprime el mediano en el antebrazo proximal. El braquiorradial es un supinador superficial inervado por el radial."},
            {"id":"mms_004","concepto":"compartimentos","enunciado":"¿Qué compartimento del brazo contiene los músculos flexores?","opciones":{"A":"Posterior","B":"Lateral","C":"Anterior","D":"Medial"},"correcta":"C","exp":"El compartimento anterior del brazo contiene los flexores: bíceps braquial, braquial anterior y coracobraquial. Inervados por el musculocutáneo. El compartimento posterior contiene el tríceps (extensor), inervado por el radial."},
            {"id":"mms_005","concepto":"manguito rotador vs deltoides","enunciado":"¿Cuál es la diferencia funcional entre el deltoides y el manguito rotador?","opciones":{"A":"Ambos solo elevan el brazo","B":"Deltoides: potencia de abducción; manguito: estabilidad y rotación de la cabeza humeral","C":"Deltoides: rotación interna; manguito: rotación externa","D":"No hay diferencia funcional significativa"},"correcta":"B","exp":"El deltoides (fibras medias) es el principal motor de la abducción del hombro (15-180°). El manguito rotador estabiliza la cabeza humeral en la cavidad glenoidea (evita el ascenso) y realiza las rotaciones. Son complementarios."},
            {"id":"mms_006","concepto":"bíceps largo","enunciado":"¿Dónde se origina la cabeza LARGA del bíceps braquial?","opciones":{"A":"Apófisis coracoides de la escápula","B":"Tubérculo supraglenoideo de la escápula","C":"Cara anterior del húmero","D":"Epicóndilo lateral del húmero"},"correcta":"B","exp":"La cabeza larga del bíceps se origina en el tubérculo supraglenoideo de la escápula. Su tendón pasa por la corredera bicipital del húmero. La cabeza corta se origina en la apófisis coracoides (junto con el coracobraquial)."},
            {"id":"mms_007","concepto":"extensores muñeca","enunciado":"Los extensores del carpo/muñeca se insertan en el:","opciones":{"A":"Epicóndilo medial (epitróclea)","B":"Epicóndilo lateral","C":"Troquíter del húmero","D":"Radio distal"},"correcta":"B","exp":"Los extensores del carpo (radiales largo y corto, cubital posterior) se originan en el epicóndilo lateral. La epicondilitis lateral ('codo de tenista') es la inflamación de estas inserciones. Los FLEXORES se originan en el epicóndilo medial (epitróclea)."},
        ]
    },
    "musculos_mi": {
        "nombre": "Músculos Miembro Inferior", "nivel": 2, "categoria": "Miembro Inferior",
        "preguntas": [
            {"id":"mmi_001","concepto":"cuádriceps","enunciado":"¿Cuántas cabezas tiene el músculo cuádriceps femoral?","opciones":{"A":"2","B":"3","C":"4","D":"5"},"correcta":"C","exp":"El cuádriceps tiene 4 cabezas: recto femoral (biarticularr: también flexor de cadera), vasto medial, vasto lateral y vasto intermedio. Todas convergen en el tendón cuadricipital → rótula → tendón rotuliano → tuberosidad tibial. Extensor de la rodilla."},
            {"id":"mmi_002","concepto":"isquiotibiales","enunciado":"Los músculos isquiotibiales son:","opciones":{"A":"Cuádriceps, sartorio y grácil","B":"Bíceps femoral, semitendinoso y semimembranoso","C":"Glúteo mayor, medio y menor","D":"Aductores del muslo"},"correcta":"B","exp":"Los isquiotibiales (cara posterior del muslo): bíceps femoral (2 cabezas), semitendinoso y semimembranoso. Se originan en la tuberosidad isquiática. Función: flexión de rodilla + extensión de cadera. Inervados por el nervio ciático."},
            {"id":"mmi_003","concepto":"glúteos","enunciado":"¿Cuál es la función principal del glúteo medio?","opciones":{"A":"Extensión de la cadera","B":"Abducción de la cadera y estabilización de la pelvis","C":"Rotación externa de la cadera","D":"Flexión de la cadera"},"correcta":"B","exp":"El glúteo medio (y menor) son los principales abductores de la cadera. Estabilizan la pelvis durante la marcha (fase monopodal). Su parálisis → marcha de Trendelenburg (la pelvis cae hacia el lado contralateral al apoyar). Inervados por el nervio glúteo superior."},
            {"id":"mmi_004","concepto":"iliopsoas","enunciado":"El músculo iliopsoas está formado por:","opciones":{"A":"Ilíaco + recto femoral","B":"Ilíaco + psoas mayor","C":"Psoas mayor + psoas menor","D":"Ilíaco + pectíneo"},"correcta":"B","exp":"El iliopsoas = ilíaco (fosa ilíaca) + psoas mayor (cuerpos T12-L4). Se unen y se insertan en el trocánter menor del fémur. Es el flexor de cadera más potente. Inervado por el nervio femoral y ramas directas del plexo lumbar (L1-L4)."},
            {"id":"mmi_005","concepto":"sartorio","enunciado":"¿Cuál es el músculo más largo del cuerpo?","opciones":{"A":"Bíceps femoral","B":"Gracilis","C":"Sartorio","D":"Semitendinoso"},"correcta":"C","exp":"El sartorio es el músculo más largo del cuerpo (atraviesa dos articulaciones: cadera y rodilla). Va desde la EIAS hasta la cara medial de la tibia. Forma la 'pata de ganso' junto con el grácil y semitendinoso. Hace flexión, abducción y rotación externa de cadera + flexión de rodilla."},
            {"id":"mmi_006","concepto":"tríceps sural","enunciado":"El tendón de Aquiles es el tendón del:","opciones":{"A":"Tibial posterior","B":"Peroneo largo","C":"Tríceps sural (gemelos + sóleo)","D":"Flexor largo de los dedos"},"correcta":"C","exp":"El tendón de Aquiles = tendón del tríceps sural (gastrocnemios/gemelos + sóleo). Se inserta en el calcáneo. Es el tendón más grueso del cuerpo. Su rotura (ruido de latigazo, signo de Thompson positivo) es frecuente en deportistas mayores de 35 años."},
            {"id":"mmi_007","concepto":"marcha Trendelenburg","enunciado":"La marcha de Trendelenburg se produce por parálisis del:","opciones":{"A":"Cuádriceps","B":"Glúteo mayor","C":"Glúteo medio","D":"Iliopsoas"},"correcta":"C","exp":"La marcha de Trendelenburg: la pelvis cae hacia el lado SANO al levantar la pierna (porque el glúteo medio del lado LESIONADO no puede sostener la pelvis). El paciente inclina el tronco hacia el lado lesionado para compensar. Causas: parálisis del nervio glúteo superior, displasia de cadera, fractura de cuello femoral."},
        ]
    },
    "arterias_ms_mi": {
        "nombre": "Arterias Miembro Superior e Inferior", "nivel": 2, "categoria": "Miembro Superior / Inferior",
        "preguntas": [
            {"id":"art_001","concepto":"arteria braquial","enunciado":"¿Cómo se denomina la arteria que pasa por el canal de Hunter (aductores) en el muslo?","opciones":{"A":"Arteria ilíaca externa","B":"Arteria femoral","C":"Arteria poplítea","D":"Arteria obturatriz"},"correcta":"B","exp":"La arteria femoral (continuación de la ilíaca externa) pasa por el triángulo de Scarpa y luego por el canal de Hunter (canal de los aductores) para convertirse en arteria poplítea al atravesar el hiato del aductor mayor."},
            {"id":"art_002","concepto":"pulso radial","enunciado":"¿Dónde se toma el pulso de la arteria radial?","opciones":{"A":"En la tabaquera anatómica y en la cara volar lateral de la muñeca","B":"En el pliegue del codo","C":"En la axila","D":"En la cara medial de la muñeca"},"correcta":"A","exp":"El pulso radial se toma en la cara anterolateral de la muñeca (entre el tendón del flexor radial del carpo y el proceso estiloides del radio), o en la tabaquera anatómica. Es el lugar más común para tomar el pulso."},
            {"id":"art_003","concepto":"arteria poplítea","enunciado":"La arteria poplítea se divide en:","opciones":{"A":"Femoral superficial y profunda","B":"Tibial anterior y tronco tibioperoneal","C":"Tibial anterior y posterior directamente","D":"Peroné y tibial posterior"},"correcta":"B","exp":"La arteria poplítea se bifurca en: arteria tibial anterior (atraviesa la membrana interósea → dorso del pie → arteria dorsal del pie) y tronco tibioperoneal (que se divide en tibial posterior y arteria peroneal/fibular)."},
            {"id":"art_004","concepto":"arteria femoral","enunciado":"¿Dónde se palpa el pulso femoral?","opciones":{"A":"En el trocánter mayor","B":"En el punto medio del ligamento inguinal","C":"En la cara interna del muslo","D":"En el triángulo poplíteo"},"correcta":"B","exp":"El pulso femoral se palpa en el punto medio del ligamento inguinal (entre la EIAS y la sínfisis del pubis). El triángulo de Scarpa está delimitado por: ligamento inguinal (base), sartorio (lateral) y aductor largo (medial). Contiene: arteria + vena + nervio femoral (de lateral a medial: NAV)."},
            {"id":"art_005","concepto":"arteria axilar","enunciado":"La arteria axilar se convierte en arteria braquial a nivel de:","opciones":{"A":"Clavícula","B":"Borde inferior del músculo pectoral menor","C":"Borde inferior del músculo redondo mayor","D":"Pliegue del codo"},"correcta":"C","exp":"La arteria subclavia se convierte en axilar al pasar bajo la clavícula. La arteria axilar se convierte en braquial al cruzar el borde inferior del músculo redondo mayor (teres major). La braquial se divide en radial y cubital a nivel del pliegue del codo."},
            {"id":"art_006","concepto":"isquemia","enunciado":"En oclusión aguda de arteria periférica, ¿cuáles son las '6 P' de la isquemia?","opciones":{"A":"Palidez, pulso, presión, parestesias, paresia, profundidad","B":"Pain (dolor), Pallor (palidez), Pulselessness, Paresthesia, Paralysis, Poikilothermia","C":"Presión, Palidez, Parestesias, Paresia, Palpación, Presión","D":"Pulso, Palidez, Purpura, Paresis, Pain, Profundidad"},"correcta":"B","exp":"Las 6P de la isquemia aguda de extremidad: Pain (dolor), Pallor (palidez), Pulselessness (ausencia de pulso), Paresthesia (parestesias), Paralysis (parálisis), Poikilothermia (frialdad). La parálisis y anestesia indican isquemia grave con lesión nerviosa inminente."},
            {"id":"art_007","concepto":"arteria tibial posterior","enunciado":"¿Dónde se palpa el pulso de la arteria tibial posterior?","opciones":{"A":"Cara anterior del tobillo","B":"Dorso del pie entre 1er y 2er metatarsianos","C":"Cara posterior del maléolo medial","D":"Espacio poplíteo"},"correcta":"C","exp":"La arteria tibial posterior se palpa en la cara posterior del maléolo medial (entre el maléolo y el tendón de Aquiles). La arteria dorsal del pie (tibial anterior) se palpa en el dorso del pie entre los tendones del 1er y 2do dedo."},
        ]
    },
    "articulacion_hombro": {
        "nombre": "Articulación del Hombro", "nivel": 2, "categoria": "Miembro Superior",
        "preguntas": [
            {"id":"ah_001","concepto":"tipo articulación","enunciado":"La articulación glenohumeral es de tipo:","opciones":{"A":"Condílea (elipsoidea)","B":"Enartrosis (esférica o cotiloidea)","C":"Troclear","D":"Artrodia (plana)"},"correcta":"B","exp":"La glenohumeral es una enartrosis (articulación esférica): 3 ejes, 3 planos, máxima movilidad pero mínima estabilidad ósea. Por eso es la articulación que más se luxa. La estabilidad depende de: cápsula, labrum glenoideo, ligamentos glenohumerales y manguito rotador."},
            {"id":"ah_002","concepto":"labrum","enunciado":"¿Cuál es la función del labrum glenoideo?","opciones":{"A":"Separar la articulación en dos cámaras","B":"Profundizar la cavidad glenoidea y aumentar la estabilidad","C":"Lubricar la articulación","D":"Transmitir cargas axiales"},"correcta":"B","exp":"El labrum glenoideo es un rodete fibrocartilaginoso que rodea la cavidad glenoidea, profundizándola (de plana a cóncava). Aumenta la superficie de contacto un 70%. La lesión de Bankart = arrancamiento del labrum anteroinferior en luxaciones anteriores."},
            {"id":"ah_003","concepto":"luxación hombro","enunciado":"¿Cuál es la dirección más frecuente de la luxación de hombro?","opciones":{"A":"Posterior","B":"Inferior (luxatio erecta)","C":"Anterior","D":"Superior"},"correcta":"C","exp":"El 95% de las luxaciones de hombro son anteriores (subcoracoidea). La cabeza humeral queda anterior al glenoide. Mecanismo: caída con el brazo en abducción y rotación externa. Riesgo de lesión del nervio axilar y arteria axilar."},
            {"id":"ah_004","concepto":"acromioclavicular","enunciado":"La articulación acromioclavicular es de tipo:","opciones":{"A":"Enartrosis","B":"Artrodia (plana)","C":"Troclear","D":"En silla de montar"},"correcta":"B","exp":"La articulación acromioclavicular (AC) es una artrodia (articulación plana): permite deslizamiento en todos los planos pero con movilidad limitada. Se lesiona en caídas sobre el hombro (separación AC). El ligamento coracoclavicular estabiliza la articulación."},
            {"id":"ah_005","concepto":"nervio axilar","enunciado":"¿Qué músculo inerva el nervio axilar?","opciones":{"A":"Supraespinoso e infraespinoso","B":"Deltoides y teres minor","C":"Subescapular y teres major","D":"Bíceps y coracobraquial"},"correcta":"B","exp":"El nervio axilar (C5-C6, del fascículo posterior) inerva el deltoides y el teres minor (parte del manguito rotador). Rodea el cuello quirúrgico del húmero → riesgo de lesión en fracturas del cuello humeral o luxaciones anteriores de hombro."},
            {"id":"ah_006","concepto":"bursa subacromial","enunciado":"La bursitis más frecuente del hombro afecta a la bursa:","opciones":{"A":"Subcoracoidea","B":"Subdeltoidea / subacromial","C":"Bicipitorradial","D":"Escapulocostal"},"correcta":"B","exp":"La bursa subacromial-subdeltoidea es la más grande del cuerpo y la más frecuentemente afectada en el hombro. Se inflama en el síndrome de atrapamiento subacromial (junto con el tendón del supraespinoso). Dolor a la abducción de 60-120°."},
            {"id":"ah_007","concepto":"arco de movimiento","enunciado":"El rango normal de abducción del hombro es aproximadamente:","opciones":{"A":"90°","B":"120°","C":"160-180°","D":"270°"},"correcta":"C","exp":"Abducción del hombro: 0-180°. De 0-15° = supraespinoso. De 15-90° = deltoides (glenohumeral). De 90-180° = escápula rota (ritmo escapulohumeral 2:1). Sin rotación escapular, la abducción quedaría bloqueada a 90° por el troquíter contra el acromion."},
        ]
    },
    "ligamentos_columna": {
        "nombre": "Ligamentos de la Columna", "nivel": 2, "categoria": "Vértebras",
        "preguntas": [
            {"id":"lc_001","concepto":"LLA","enunciado":"¿Qué movimiento de la columna previene el ligamento longitudinal ANTERIOR (LLA)?","opciones":{"A":"La hiperflexión","B":"La hiperextensión","C":"La rotación excesiva","D":"La lateralización"},"correcta":"B","exp":"El LLA (ligamento longitudinal anterior) va por la cara anterior de los cuerpos vertebrales. Previene la hiperextensión de la columna. Es el ligamento más resistente de la columna. Se tensa en extensión."},
            {"id":"lc_002","concepto":"LLP","enunciado":"El ligamento longitudinal POSTERIOR (LLP) se localiza en:","opciones":{"A":"Cara anterior de los cuerpos vertebrales","B":"Cara posterior de los cuerpos vertebrales (dentro del canal raquídeo)","C":"Entre las láminas vertebrales","D":"Entre las apófisis espinosas"},"correcta":"B","exp":"El LLP va por la cara posterior de los cuerpos vertebrales, dentro del canal raquídeo. Previene la hiperflexión y contiene el núcleo pulposo. Es más débil en su parte posterolateral → las hernias discales suelen ser posterolaterales."},
            {"id":"lc_003","concepto":"ligamento amarillo","enunciado":"¿Qué tipo de fibras predomina en el ligamento amarillo (flavum)?","opciones":{"A":"Fibras de colágeno tipo I","B":"Fibras elásticas (elastina)","C":"Fibras de colágeno tipo II","D":"Fibrocartílago"},"correcta":"B","exp":"El ligamento flavum (amarillo) contiene 80% de fibras elásticas → le da su color amarillo. Une las láminas de vértebras adyacentes. Su hipertrofia (estenosis de canal) es causa frecuente de estenosis espinal lumbar en mayores. Se tensa en flexión."},
            {"id":"lc_004","concepto":"ligamento flavum","enunciado":"¿Qué ligamento se perfora en la punción lumbar/epidural?","opciones":{"A":"Ligamento supraespinoso","B":"Ligamento interespinoso","C":"Ligamento longitudinal posterior","D":"Ligamento flavum (amarillo)"},"correcta":"D","exp":"En la punción epidural lumbar, la aguja perfora: piel → tejido subcutáneo → ligamento supraespinoso → ligamento interespinoso → ligamento flavum → espacio epidural. La sensación de 'pérdida de resistencia' al atravesar el flavum confirma la entrada al espacio epidural."},
            {"id":"lc_005","concepto":"ligamento nucal","enunciado":"¿Cómo se denomina el ligamento supraespinoso en la región cervical?","opciones":{"A":"Ligamento flavum cervical","B":"Ligamento nucal (nuca)","C":"Ligamento transverso del atlas","D":"Membrana atlantooccipital"},"correcta":"B","exp":"El ligamento nucal es la extensión cervical del ligamento supraespinoso, pero es mucho más grueso y fibroso. Va desde la protuberancia occipital externa hasta C7. En cuadrúpedos es muy desarrollado para soportar el peso de la cabeza."},
            {"id":"lc_006","concepto":"inestabilidad columna","enunciado":"¿Cuántos 'pilares' de la columna pueden lesionarse antes de que sea inestable (concepto de Denis)?","opciones":{"A":"Si se lesiona 1 pilar","B":"Si se lesionan 2 o 3 pilares","C":"Solo si se lesionan los 3 pilares","D":"La inestabilidad no depende del número de pilares"},"correcta":"B","exp":"Denis divide la columna en 3 columnas: anterior (LLA + mitad anterior del disco y cuerpo), media (mitad posterior del cuerpo + LLP), posterior (arcos posteriores + ligamentos posteriores). Si se lesionan 2 o más columnas → inestabilidad. La columna media es la clave."},
            {"id":"lc_007","concepto":"discectomía","enunciado":"¿Qué ligamento actúa como barrera natural conteniendo el núcleo pulposo?","opciones":{"A":"Ligamento longitudinal anterior","B":"Ligamento transverso","C":"Anillo fibroso del disco","D":"Ligamento interespinoso"},"correcta":"C","exp":"El anillo fibroso (fibras de colágeno oblicuas en capas concéntricas) es la barrera que contiene el núcleo pulposo. Cuando el anillo se rompe, el núcleo pulposo se hernia → compresión de raíces nerviosas. La hernia posterolateral es la más frecuente porque el anillo es más débil aquí y el LLP no llega."},
        ]
    },
    "articulacion_codo": {
        "nombre": "Articulación del Codo", "nivel": 3, "categoria": "Miembro Superior",
        "preguntas": [
            {"id":"ac_001","concepto":"anatomía codo","enunciado":"¿Cuántos huesos participan en la articulación del codo?","opciones":{"A":"2 (húmero y radio)","B":"2 (húmero y cúbito)","C":"3 (húmero, radio y cúbito)","D":"4 huesos"},"correcta":"C","exp":"La articulación del codo está formada por 3 huesos: húmero + radio + cúbito. Comprende 3 articulaciones en una cápsula: humerocubital (troclear, flexoextensión), humeroradial (condílea) y radiocubital proximal (trocoidea, pronosupinación)."},
            {"id":"ac_002","concepto":"nervio cubital","enunciado":"¿Por qué zona pasa el nervio cubital a nivel del codo?","opciones":{"A":"Por delante del epicóndilo medial","B":"Por el surco del nervio cubital (epitrócleo-olecraniano)","C":"Por el canal carpiano","D":"Por la fosa antecubital"},"correcta":"B","exp":"El nervio cubital (ulnar) pasa por el surco del nervio cubital, entre el epicóndilo medial (epitróclea) y el olécranon. Es muy superficial aquí → vulnerable. Al golpearse el 'hueso de la alegría' (nervio cubital), se siente el hormigueo en 4º-5º dedos."},
            {"id":"ac_003","concepto":"epicondilitis","enunciado":"La epicondilitis LATERAL ('codo de tenista') afecta a los tendones de los:","opciones":{"A":"Flexores del carpo (epitróclea)","B":"Extensores del carpo (epicóndilo lateral)","C":"Pronadores del antebrazo","D":"Flexores de los dedos"},"correcta":"B","exp":"Epicondilitis lateral (codo de tenista): inflamación crónica en el origen de los extensores del carpo en el epicóndilo lateral. Dolor al extender la muñeca contra resistencia. La EPITROCLEITIS (codo de golfista) afecta los flexores en el epicóndilo medial."},
            {"id":"ac_004","concepto":"fosa cubital","enunciado":"La fosa antecubital (cubital anterior) contiene de lateral a medial:","opciones":{"A":"Nervio mediano, arteria braquial, tendón del bíceps","B":"Tendón del bíceps, arteria braquial, nervio mediano","C":"Arteria radial, vena mediana, nervio cubital","D":"Nervio radial, arteria braquial, nervio mediano"},"correcta":"B","exp":"La fosa antecubital (fosa del codo) contiene de lateral a medial: Tendón del bíceps - Arteria braquial (con sus venas) - Nervio mediano. El nervio radial no está en la fosa propiamente dicha (pasa lateral). Nemotecnia: BAN (Bíceps-Arteria-Nervio)."},
            {"id":"ac_005","concepto":"luxación codo","enunciado":"La luxación del codo más frecuente es hacia:","opciones":{"A":"Anterior","B":"Medial","C":"Posterior","D":"Lateral"},"correcta":"C","exp":"La luxación posterior del codo es la más frecuente (90%). Ocurre por caída sobre la mano extendida con el codo en extensión. El radio y el cúbito se desplazan posteriormente al húmero. En niños, la 'cabeza radial subluxada' (nursemaid's elbow) es la lesión más frecuente del codo."},
        ]
    },
    "disco_intervertebral": {
        "nombre": "Disco Intervertebral", "nivel": 3, "categoria": "Vértebras",
        "preguntas": [
            {"id":"di_001","concepto":"estructura disco","enunciado":"¿Cuáles son las dos partes del disco intervertebral?","opciones":{"A":"Cartílago hialino y fibrocartílago","B":"Núcleo pulposo y anillo fibroso","C":"Ligamento y cartílago","D":"Hueso esponjoso y cortical"},"correcta":"B","exp":"El disco intervertebral tiene: Anillo fibroso (capas concéntricas de fibras de colágeno oblicuas, más grueso anterior y lateralmente) + Núcleo pulposo (gel hidrofílico de proteoglicanos, remanente de la notocorda, hidratado al 80%)."},
            {"id":"di_002","concepto":"hernia discal","enunciado":"¿Cuál es el nivel más frecuente de hernia discal lumbar?","opciones":{"A":"L1-L2","B":"L2-L3","C":"L3-L4","D":"L4-L5 y L5-S1"},"correcta":"D","exp":"El 95% de las hernias lumbares ocurren en L4-L5 y L5-S1. La hernia L4-L5 comprime la raíz L5 (pie caído, extensión del 1er dedo). La hernia L5-S1 comprime S1 (pérdida del reflejo aquíleo, debilidad de la flexión plantar)."},
            {"id":"di_003","concepto":"notocorda","enunciado":"El núcleo pulposo es un remanente de:","opciones":{"A":"El periostio embrionario","B":"La notocorda","C":"El mesodermo paraxial","D":"El ectodermo"},"correcta":"B","exp":"El núcleo pulposo es un remanente de la notocorda (estructura embrionaria que induce la formación del sistema nervioso central). Es un gel altamente hidrofílico que actúa como amortiguador de impactos. Se deshidrata con la edad (reducción de altura discal)."},
            {"id":"di_004","concepto":"dirección hernia","enunciado":"¿Por qué la mayoría de las hernias discales son posterolaterales?","opciones":{"A":"Por la forma de los músculos paravertebrales","B":"Porque el anillo fibroso es más débil posterolateralmente y el LLP no cubre esa zona","C":"Porque el LLA es muy grueso y refuerza la parte anterior","D":"Por el movimiento predominante de rotación"},"correcta":"B","exp":"Las hernias discales son posterolaterales porque: 1) el anillo fibroso tiene fibras más escasas en su parte posterolateral, 2) el ligamento longitudinal posterior (LLP) es más estrecho y no cubre esa zona. Por eso comprimen la raíz nerviosa del nivel inferior (la que ya ha salido por el foramen)."},
            {"id":"di_005","concepto":"síndrome cauda equina","enunciado":"Una hernia discal masiva central que comprime la cauda equina produce:","opciones":{"A":"Monoparesia de un miembro","B":"Anestesia en silla de montar + disfunción esfinteriana","C":"Solo dolor lumbar sin déficit neurológico","D":"Parálisis de los cuádriceps bilateralmente"},"correcta":"B","exp":"El síndrome de la cauda equina es una URGENCIA QUIRÚRGICA: hernia discal central masiva que comprime todas las raíces L2-S5. Produce: anestesia perineal en 'silla de montar', incontinencia/retención urinaria y fecal, paresia de extremidades. Requiere descompresión urgente (<24h)."},
        ]
    },
    "suturas_fosas": {
        "nombre": "Suturas y Fosas Craneales", "nivel": 3, "categoria": "Cráneo",
        "preguntas": [
            {"id":"sf_001","concepto":"suturas","enunciado":"¿Qué sutura une los dos huesos parietales?","opciones":{"A":"Sutura coronal","B":"Sutura sagital","C":"Sutura lambdoidea","D":"Sutura escamosa"},"correcta":"B","exp":"Sutura sagital: une los dos parietales (en la línea media del cráneo). Sutura coronal: frontal + parietales. Sutura lambdoidea: parietales + occipital. Sutura escamosa: parietal + temporal."},
            {"id":"sf_002","concepto":"fontanelas","enunciado":"La fontanela anterior (bregmática) cierra normalmente a los:","opciones":{"A":"3-6 meses","B":"6-12 meses","C":"18-24 meses","D":"3-4 años"},"correcta":"C","exp":"La fontanela anterior (bregmática, en el bregma = unión sagital+coronal) es la mayor. Cierra entre 18-24 meses. La fontanela posterior (lambda) cierra a los 2-3 meses. La fontanela tensa y abombada en un lactante sugiere hipertensión intracraneal."},
            {"id":"sf_003","concepto":"fosas craneales","enunciado":"¿Qué estructura forma el suelo de la fosa craneal POSTERIOR?","opciones":{"A":"Ala mayor del esfenoides","B":"Porción orbitaria del frontal","C":"Porción petrosa del temporal y occipital","D":"Cuerpo del esfenoides"},"correcta":"C","exp":"Fosa posterior: formada por la porción petrosa del temporal + occipital. Aloja cerebelo, puente y bulbo raquídeo. Es la más profunda y pequeña. Delimitada anteriormente por el dorso de la silla turca; cubierta por el tentorio del cerebelo."},
            {"id":"sf_004","concepto":"craneostosis","enunciado":"El cierre prematuro de la sutura sagital (escafocefalia) produce:","opciones":{"A":"Cráneo corto y ancho","B":"Cráneo largo y estrecho (dolicocéfalo)","C":"Asimetría craneal (plagiocefalia)","D":"Cráneo en torre (turricefalia)"},"correcta":"B","exp":"Craneosinostosis sagital (más frecuente): el cráneo crece en dirección anteroposterior compensatoriamente → dolicocefalia (cráneo largo y estrecho). Si se cierra la sutura coronal: braquicefalia (corto y ancho). Si es unilateral: plagiocefalia."},
            {"id":"sf_005","concepto":"hematoma epidural","enunciado":"El hematoma epidural clásico produce un intervalo lúcido porque:","opciones":{"A":"El sangrado es venoso y lento","B":"El sangrado arterial (meníngea media) forma un hematoma que inicialmente no comprime la corteza","C":"La lesión es infratentorial","D":"El hematoma es crónico"},"correcta":"B","exp":"Hematoma epidural: hemorragia arterial (arteria meníngea media, tras fractura del ptérion) entre el cráneo y la duramadre. Clásico: TCE → pérdida de consciencia breve → intervalo lúcido (horas) → deterioro neurológico rápido por efecto de masa. Es una urgencia neuroquirúrgica."},
        ]
    },
}

# ── EXTENSIÓN: preguntas adicionales de calidad MIR ──────────────
_EXTRA = {
    "manguito_rotador": [
        {"id":"mr_011","concepto":"test clínico subescapular","enunciado":"El test de Gerber (lift-off test) valora la integridad del:","opciones":{"A":"Supraespinoso","B":"Infraespinoso","C":"Subescapular","D":"Teres minor"},"correcta":"C","exp":"El lift-off test de Gerber: el paciente coloca la mano en la espalda y la separa. Si no puede → subescapular roto. Es el test específico para el subescapular, el único rotador interno del manguito."},
        {"id":"mr_012","concepto":"impingement subacromial","enunciado":"El síndrome de atrapamiento subacromial (impingement) se caracteriza por dolor en el arco de abducción de:","opciones":{"A":"0 a 30°","B":"60 a 120°","C":"90 a 180°","D":"0 a 60°"},"correcta":"B","exp":"El arco doloroso de Neer ocurre entre 60-120° de abducción, cuando el troquíter y el supraespinoso rozan el arco coracoacromial. Por encima de 120° la escápula rota y cesa el dolor."},
        {"id":"mr_013","concepto":"lesión de Bankart","enunciado":"La lesión de Bankart que ocurre en las luxaciones anteriores de hombro afecta al:","opciones":{"A":"Tendón del supraespinoso","B":"Labrum glenoideo anteroinferior","C":"Ligamento coracoacromial","D":"Tendón de la cabeza larga del bíceps"},"correcta":"B","exp":"La lesión de Bankart es el arrancamiento del labrum glenoideo anteroinferior, ocurre en el 90% de las luxaciones anteriores de hombro. Predispone a recidiva. Se asocia a lesión de Hill-Sachs (impactación de la cabeza humeral posterior)."},
        {"id":"mr_014","concepto":"rotura manguito rotador","enunciado":"Un paciente de 65 años no puede iniciar la abducción activa del hombro pero sí puede mantenerla si se le coloca el brazo. ¿Qué estructura está rota?","opciones":{"A":"Deltoides","B":"Nervio axilar","C":"Tendón del supraespinoso","D":"Tendón del infraespinoso"},"correcta":"C","exp":"La rotura completa del supraespinoso impide iniciar la abducción (0-15°) porque es el iniciador. Sin embargo, si el deltoides coloca el brazo en abducción mayor de 15°, el paciente puede mantener la posición. Signo de 'brazo caído' en roturas masivas."},
        {"id":"mr_015","concepto":"calcificación manguito","enunciado":"¿Cuál es el tendón del manguito donde se forman calcificaciones con mayor frecuencia?","opciones":{"A":"Infraespinoso","B":"Subescapular","C":"Teres minor","D":"Supraespinoso"},"correcta":"D","exp":"Las calcificaciones del manguito (tendinitis calcificante) afectan principalmente al supraespinoso (zona hipovascular crítica de Codman, a 1 cm de su inserción en el troquíter). Son depósitos de hidroxiapatita que causan dolor agudo intenso."},
    ],
    "plexo_braquial": [
        {"id":"pb_011","concepto":"nervio axilar","enunciado":"Un paciente presenta incapacidad para abducir el hombro más de 15° tras una luxación anterior de hombro. ¿Qué nervio está lesionado?","opciones":{"A":"Nervio supraescapular","B":"Nervio musculocutáneo","C":"Nervio axilar","D":"Nervio radial"},"correcta":"C","exp":"El nervio axilar (C5-C6) rodea el cuello quirúrgico del húmero y es el más frecuentemente lesionado en luxaciones anteriores de hombro (10-18%). Inerva el deltoides (abducción) y teres minor. Anestesia en zona del sargento (cara lateral del brazo)."},
        {"id":"pb_012","concepto":"nervio radial","enunciado":"Fractura de la diáfisis humeral en su tercio medio. ¿Qué lesión neurológica esperarías?","opciones":{"A":"Parálisis del nervio cubital: mano en garra","B":"Parálisis del nervio mediano: mano de predicador","C":"Parálisis del nervio radial: mano caída (wrist drop)","D":"Parálisis del nervio axilar: imposibilidad de abducción"},"correcta":"C","exp":"El nervio radial pasa por el surco de torsión humeral en el tercio medio. Las fracturas de diáfisis humeral (especialmente en el 1/3 medio) lesionan el radial en un 10-18% → parálisis de extensores de muñeca y dedos → 'mano caída'. Suele recuperarse."},
        {"id":"pb_013","concepto":"síndrome del túnel carpiano","enunciado":"Paciente con hormigueo nocturno en los 3 primeros dedos y la mitad radial del 4º. Test de Phalen positivo. ¿Qué nervio está comprimido?","opciones":{"A":"Nervio cubital","B":"Nervio radial","C":"Nervio mediano","D":"Nervio musculocutáneo"},"correcta":"C","exp":"El síndrome del túnel carpiano es la neuropatía por compresión más frecuente. El nervio mediano se comprime bajo el ligamento carpiano transverso. Da hormigueo en los 3,5 dedos radiales (pulgar, índice, corazón y mitad radial del anular). El test de Phalen (flexión palmar mantenida) y el signo de Tinel son positivos."},
        {"id":"pb_014","concepto":"lesión nervio cubital codo","enunciado":"Paciente con fractura de olécranon. Refiere pérdida de sensibilidad en el 5º dedo y mitad cubital del 4º. ¿Qué nervio está lesionado?","opciones":{"A":"Nervio mediano","B":"Nervio radial","C":"Nervio cubital","D":"Nervio interóseo anterior"},"correcta":"C","exp":"El nervio cubital pasa por el surco epitrócleo-olecraniano. Las fracturas/luxaciones del codo o la presión crónica lo lesionan (codo de los cubistas). Pérdida de sensibilidad en 1,5 dedos cubitales + debilidad de intrínsecos + 'garra' en 4º-5º dedos."},
        {"id":"pb_015","concepto":"desfiladero torácico","enunciado":"El síndrome del desfiladero torácico puede comprimir el plexo braquial a nivel de:","opciones":{"A":"El canal carpiano","B":"Entre el músculo escaleno anterior y la primera costilla","C":"El surco de torsión del húmero","D":"El hiato del aductor"},"correcta":"B","exp":"El síndrome del desfiladero torácico comprime el plexo braquial (y/o la arteria subclavia) entre el músculo escaleno anterior, el escaleno medio y la 1ª costilla (o costilla cervical). Síntomas: dolor, parestesias y debilidad en todo el brazo."},
    ],
    "huesos_ms": [
        {"id":"hms_011","concepto":"fractura Monteggia","enunciado":"La fractura de Monteggia consiste en:","opciones":{"A":"Fractura del radio distal con desplazamiento dorsal","B":"Fractura del cúbito proximal con luxación de la cabeza radial","C":"Fractura de la cabeza del radio","D":"Fractura del escafoides"},"correcta":"B","exp":"Fractura de Monteggia: fractura del tercio proximal del CÚBITO + luxación de la cabeza RADIAL. Mecanismo: caída sobre el codo en extensión. Regla: CUbito Luxación Radial. Lo contrario es la fractura de Galeazzi: fractura del RADIO distal + luxación de la cabeza cubital."},
        {"id":"hms_012","concepto":"fractura Galeazzi","enunciado":"La fractura de Galeazzi se caracteriza por:","opciones":{"A":"Fractura del cúbito + luxación de la cabeza radial","B":"Fractura del tercio distal del radio + luxación de la articulación radiocubital distal","C":"Fractura de ambos huesos del antebrazo en su tercio medio","D":"Fractura de la estiloides radial"},"correcta":"B","exp":"Galeazzi: fractura del RADIO en su tercio distal + luxación de la articulación RADIOCUBital DISTAL. Afecta el cúbito distal. Nemotecnia: Galeazzi = el GRANDE (radio) se fractura. Monteggia = fractura del MENOR (cúbito)."},
        {"id":"hms_013","concepto":"fractura Bennett","enunciado":"La fractura de Bennett es una fractura-luxación que afecta a:","opciones":{"A":"La base del primer metacarpiano","B":"La falange proximal del pulgar","C":"El escafoides","D":"El radio distal"},"correcta":"A","exp":"La fractura de Bennett es una fractura-luxación intraarticular de la BASE del 1er METACARPIANO (pulgar). El fragmento cubital queda fijo por el ligamento y la diáfisis se luxa radialmente por el abductor largo. Requiere reducción y fijación quirúrgica."},
        {"id":"hms_014","concepto":"osificación","enunciado":"¿Qué tipo de osificación forma los huesos largos (húmero, fémur)?","opciones":{"A":"Osificación intramembranosa","B":"Osificación endocondral","C":"Osificación perióstica directa","D":"Osificación heterotópica"},"correcta":"B","exp":"Los huesos largos se forman por osificación endocondral: primero se forma un molde cartilaginoso que luego es reemplazado por hueso. Los huesos planos del cráneo se forman por osificación intramembranosa (directamente desde tejido mesenquimal, sin molde cartilaginoso)."},
        {"id":"hms_015","concepto":"luxación acromioclavicular","enunciado":"En una separación acromioclavicular grado III (Rockwood), ¿qué ligamentos están rotos?","opciones":{"A":"Solo el ligamento acromioclavicular","B":"Solo el ligamento coracoclavicular","C":"Ligamentos acromioclavicular y coracoclavicular","D":"Ligamento coracoacromial"},"correcta":"C","exp":"Grados de separación AC: I (esguince AC), II (rotura AC + intacto coracoclavicular), III (rotura AC + coracoclavicular: clavícula 'flota'). Los grados I-II se tratan conservadoramente; el grado III y superiores frecuentemente requieren cirugía."},
    ],
    "huesos_mi": [
        {"id":"hmi_011","concepto":"fractura calcáneo","enunciado":"Un trabajador cae desde una andamio de 3 metros y aterriza de pie. ¿Cuál es la fractura más probable?","opciones":{"A":"Fractura de astrágalo","B":"Fractura de calcáneo por compresión axial","C":"Fractura de tibia distal","D":"Fractura de peroné"},"correcta":"B","exp":"Las caídas desde altura con aterrizaje sobre los pies producen fracturas del CALCÁNEO (más frecuente) por compresión axial. Se asocian con fracturas de columna lumbar (L1-L2) en el 10-15% por la energía que sube por el esqueleto axial. Buscar siempre fractura vertebral concomitante."},
        {"id":"hmi_012","concepto":"luxación cadera","enunciado":"Una luxación posterior de cadera puede lesionar el nervio:","opciones":{"A":"Femoral","B":"Obturador","C":"Ciático","D":"Glúteo superior"},"correcta":"C","exp":"La luxación posterior de cadera (la más frecuente, 90%) puede lesionar el nervio CIÁTICO en un 10-20% de casos. La cabeza femoral se desplaza hacia atrás, cerca del nervio ciático. El miembro queda en flexión, aducción y rotación interna. Es una urgencia ortopédica."},
        {"id":"hmi_013","concepto":"ángulo de Wiberg","enunciado":"¿Qué ángulo mide el grado de cobertura de la cabeza femoral por el acetábulo?","opciones":{"A":"Ángulo cervicodiafisario (de inclinación)","B":"Ángulo centro-borde de Wiberg","C":"Ángulo de anteversión femoral","D":"Ángulo de Böhler"},"correcta":"B","exp":"El ángulo centro-borde de Wiberg (>25° normal) mide la cobertura acetabular de la cabeza femoral. Si es menor de 20° = displasia de cadera. El ángulo de Böhler evalúa la columna posterior del calcáneo en fracturas. El ángulo cervicodiafisario normal es 125-135°."},
        {"id":"hmi_014","concepto":"pie plano","enunciado":"El arco longitudinal medial del pie está mantenido principalmente por:","opciones":{"A":"El tendón del tibial anterior","B":"El tendón del tibial posterior y el ligamento calcaneonavicular plantar (spring ligament)","C":"El tendón de Aquiles","D":"Los ligamentos del tobillo"},"correcta":"B","exp":"El arco longitudinal medial está sostenido por: tendón del tibial posterior (músculo más importante), ligamento calcaneonavicular plantar (spring ligament), ligamento plantar largo y la fascia plantar. La rotura del tendón del tibial posterior es la causa más frecuente de pie plano adquirido en adultos."},
        {"id":"hmi_015","concepto":"fractura de cadera","enunciado":"Una fractura subcapital del cuello femoral en adulto mayor, ¿cuál es el principal riesgo vascular?","opciones":{"A":"Lesión de la arteria femoral común","B":"Necrosis avascular de la cabeza femoral","C":"Trombosis de la vena femoral","D":"Lesión de la arteria poplítea"},"correcta":"B","exp":"La fractura subcapital del cuello femoral interrumpe las arterias circunflejas que irrigan la cabeza femoral a través del cuello → necrosis avascular de la cabeza femoral (20-30%). Por eso en mayores se prefiere la prótesis parcial de cadera en lugar de osteosíntesis. En jóvenes se intenta preservar la cabeza."},
    ],
    "nervios_mmii": [
        {"id":"nmi_011","concepto":"meralgia parestésica","enunciado":"Un paciente obeso refiere quemazón y hormigueo en la cara anterolateral del muslo, sin debilidad. ¿Qué nervio está afectado?","opciones":{"A":"Nervio femoral","B":"Nervio obturador","C":"Nervio cutáneo lateral del muslo","D":"Nervio iliohipogástrico"},"correcta":"C","exp":"La meralgia parestésica = compresión del nervio cutáneo lateral del muslo (L2-L3) bajo el ligamento inguinal, cerca de la EIAS. Sensación de quemazón y entumecimiento en cara anterolateral del muslo SIN debilidad ni pérdida de reflejos (es puramente sensitivo). Más frecuente en obesos, embarazadas, cinturones apretados."},
        {"id":"nmi_012","concepto":"síndrome del túnel del tarso","enunciado":"El síndrome del túnel del tarso produce síntomas por compresión del:","opciones":{"A":"Nervio peroneo superficial","B":"Nervio sural","C":"Nervio tibial posterior bajo el retináculo flexor del tobillo","D":"Nervio safeno"},"correcta":"C","exp":"El síndrome del túnel del tarso es la compresión del nervio tibial posterior bajo el retináculo flexor medial del tobillo (análogo al túnel carpiano pero en el pie). Produce dolor y parestesias en la planta del pie que empeoran al caminar. El signo de Tinel en la región retromaleolar medial es positivo."},
        {"id":"nmi_013","concepto":"lesión nervio peroneo","enunciado":"¿Cuál es la causa más frecuente de lesión del nervio peroneo común?","opciones":{"A":"Fractura de tibia distal","B":"Compresión en el cuello del peroné","C":"Hernia discal L4-L5","D":"Luxación de rodilla"},"correcta":"B","exp":"La causa más frecuente de lesión del nervio peroneo común es la compresión en el cuello del peroné: cruzar las piernas, yesos mal puestos, traumatismos directos. También puede lesionarse en luxaciones de rodilla. Produce pie caído + anestesia en dorso del pie y cara anterolateral de la pierna."},
        {"id":"nmi_014","concepto":"plexo lumbar","enunciado":"El nervio femoral (crural) emerge por:","opciones":{"A":"El agujero ciático mayor","B":"El canal obturador","C":"La laguna muscular, bajo el ligamento inguinal, lateral a la arteria femoral","D":"El canal de Hunter"},"correcta":"C","exp":"El nervio femoral pasa por la laguna muscular (bajo el ligamento inguinal, lateral a los vasos femorales) hacia el triángulo de Scarpa. Recordar de lateral a medial en el triángulo de Scarpa: Nervio-Arteria-Vena (NAVío). Es el nervio más lateral de los tres."},
        {"id":"nmi_015","concepto":"dermatomas MMII","enunciado":"La pérdida de sensibilidad en el borde medial del pie y el maléolo medial corresponde al dermatoma:","opciones":{"A":"L3","B":"L4","C":"L5","D":"S1"},"correcta":"B","exp":"Dermatomas del miembro inferior: L3 = cara anterior e interna del muslo. L4 = cara medial de la pierna y maléolo medial (borde medial del pie). L5 = dorso del pie y 1er espacio interdigital. S1 = talón y borde lateral del pie. El reflejo rotuliano evalúa L4; el aquíleo, S1."},
    ],
    "rodilla": [
        {"id":"rod_011","concepto":"McMurray","enunciado":"El test de McMurray positivo indica lesión de:","opciones":{"A":"Ligamento cruzado anterior","B":"Ligamento colateral medial","C":"Menisco","D":"Tendón rotuliano"},"correcta":"C","exp":"El test de McMurray evalúa los meniscos: con la rodilla en flexión máxima, se rota la tibia (externa para menisco medial, interna para lateral) mientras se extiende la rodilla. Un 'clunk' doloroso = lesión meniscal. El test de Apley (compresión axial en decúbito prono) también evalúa meniscos."},
        {"id":"rod_012","concepto":"Osgood-Schlatter","enunciado":"Un adolescente de 13 años deportista refiere dolor en la tuberosidad tibial anterior que aumenta con la actividad. ¿Cuál es el diagnóstico más probable?","opciones":{"A":"Fractura de estrés de la tibia","B":"Enfermedad de Osgood-Schlatter","C":"Rotura del tendón rotuliano","D":"Artritis séptica de rodilla"},"correcta":"B","exp":"La enfermedad de Osgood-Schlatter es una apofisitis de la tuberosidad tibial anterior por tracción repetida del tendón rotuliano durante el crecimiento. Típica en adolescentes deportistas (10-15 años). Tratamiento: reposo relativo, hielo, fisioterapia. Generalmente se resuelve al completar el crecimiento."},
        {"id":"rod_013","concepto":"quiste de Baker","enunciado":"El quiste de Baker (quiste poplíteo) se localiza en:","opciones":{"A":"Cara anterior de la rodilla","B":"Cara lateral de la rodilla","C":"Fosa poplítea, cara posterior de la rodilla","D":"Cara medial de la rodilla"},"correcta":"C","exp":"El quiste de Baker es una bursitis de la bursa semimembranosa-gastrocnemio en la fosa poplítea. Se asocia a derrame intraarticular crónico (artrosis, artritis reumatoide, lesión meniscal). Puede romperse simulando una trombosis venosa profunda ('pseudotromboflebitis')."},
        {"id":"rod_014","concepto":"artroplastia rodilla","enunciado":"En la artroplastia total de rodilla, ¿qué estructura se conserva para mantener la estabilidad?","opciones":{"A":"Ligamento cruzado anterior","B":"Meniscos","C":"Ligamento cruzado posterior (en algunos diseños)","D":"Ligamento colateral lateral"},"correcta":"C","exp":"En la prótesis total de rodilla convencional se sacrifican los meniscos y el LCA. Algunos diseños 'cruciate-retaining' (CR) conservan el LCP para mantener la cinemática de rodadura del fémur. Otros diseños 'posterior-stabilized' (PS) sacrifican el LCP y usan un tope central que lo sustituye."},
        {"id":"rod_015","concepto":"fractura rótula","enunciado":"Una fractura transversa de rótula con incapacidad para extender la rodilla requiere:","opciones":{"A":"Tratamiento conservador con yeso","B":"Cirugía urgente (osteosíntesis) para restaurar el aparato extensor","C":"Solo fisioterapia","D":"Rodillera articulada"},"correcta":"B","exp":"Una fractura de rótula con desplazamiento > 3mm o con incapacidad de extender la rodilla activamente (retináculos rotos) requiere CIRUGÍA: osteosíntesis con cerclaje en banda de tensión. Sin cirugía el aparato extensor queda incompetente. Las fracturas no desplazadas y con extensión activa conservada se tratan conservadoramente."},
    ],
    "huesos_craneo": [
        {"id":"hc_011","concepto":"hematoma epidural","enunciado":"Un paciente sufre un golpe en la sien, pierde la consciencia brevemente, y 2 horas después entra en coma. La TC muestra una lente biconvexa hiperdensa. ¿Cuál es el diagnóstico?","opciones":{"A":"Hematoma subdural agudo","B":"Hematoma epidural agudo","C":"Contusión cerebral","D":"Hemorragia subaracnoidea"},"correcta":"B","exp":"Hematoma EPIDURAL: imagen lenticular biconvexa en TC, no cruza suturas. Clásico intervalo lúcido (lucid interval). Sangrado de la arteria MENÍNGEA MEDIA tras fractura del ptérion (temporal). URGENCIA neuroquirúrgica: si se interviene pronto (antes del deterioro) el pronóstico es excelente."},
        {"id":"hc_012","concepto":"hematoma subdural","enunciado":"Un anciano de 80 años en tratamiento anticoagulante presenta confusión progresiva tras una caída menor hace 3 semanas. TC: imagen creciente hipodensa. ¿Diagnóstico?","opciones":{"A":"Hematoma epidural agudo","B":"Contusión cerebral tardía","C":"Hematoma subdural crónico","D":"Higroma subdural"},"correcta":"C","exp":"Hematoma SUBDURAL CRÓNICO: imagen creciente (convexo-cóncava) en TC, hipodensa en crónicos (sangre antigua). Cruza suturas. Sangrado de venas puente en anciano/anticoagulado con trauma mínimo. Puede presentarse como demencia o confusión progresiva semanas después. Evacuación por trépano."},
        {"id":"hc_013","concepto":"fractura base de cráneo","enunciado":"Un paciente con fractura de la base anterior del cráneo presenta 'ojos de mapache' y rinolicuorrea. ¿Qué estructura está dañada?","opciones":{"A":"Hueso parietal y arteria meníngea","B":"Porción petrosa del temporal","C":"Lámina cribosa del etmoides y fosa anterior","D":"Hueso esfenoides y seno cavernoso"},"correcta":"C","exp":"La fractura de la fosa craneal ANTERIOR (lámina cribosa del etmoides) produce: equimosis periorbitaria bilateral ('ojos de mapache'), rinolicuorrea (LCR por la nariz) y anosmia (lesión del I par craneal). La fractura de la base media (peñasco del temporal) produce: hemotímpano, signo de Battle (equimosis retroauricular) y otolicuorrea."},
        {"id":"hc_014","concepto":"fontanelas","enunciado":"En un lactante de 6 meses con fiebre y rigidez de nuca, la fontanela anterior está abombada. ¿Qué indica esto?","opciones":{"A":"Deshidratación","B":"Cierre prematuro de la fontanela","C":"Hipertensión intracraneal","D":"Hipotiroidismo"},"correcta":"C","exp":"La fontanela anterior abombada en un lactante = signo de HIPERTENSIÓN INTRACRANEAL (junto con fiebre y rigidez de nuca = meningitis). La fontanela hundida indica deshidratación. La fontanela normalmente está blanda y ligeramente hundida cuando el niño está tranquilo y erguido. Cierra entre 18-24 meses."},
        {"id":"hc_015","concepto":"cráneo del recién nacido","enunciado":"Los huesos del cráneo del recién nacido están separados por fontanelas para permitir el paso por el canal del parto. ¿Cuántas fontanelas tiene el recién nacido?","opciones":{"A":"2 (anterior y posterior)","B":"4 (anterior, posterior y 2 laterales)","C":"6 (anterior, posterior, 2 esfenoidales y 2 mastoideas)","D":"8 fontanelas"},"correcta":"C","exp":"El cráneo del recién nacido tiene 6 fontanelas: anterior (bregmática, la mayor, cierra 18-24m), posterior (lambdoidea, cierra 2-3m), 2 esfenoidales anteriores (ptérion, cierran a los 3m) y 2 mastoideas posteriores (astérion, cierran a los 12m). Las fontanelas permiten el moldeado durante el parto y el crecimiento cerebral."},
    ],
    "craneo_foramenes": [
        {"id":"cf_011","concepto":"seno cavernoso","enunciado":"¿Qué nervios craneales atraviesan el seno cavernoso?","opciones":{"A":"II, III, IV","B":"III, IV, V1, V2 y VI","C":"V, VI, VII","D":"VII, VIII, IX"},"correcta":"B","exp":"El seno cavernoso contiene: arteria carótida interna, III (oculomotor), IV (troclear), VI (abducens) en su interior, y V1 y V2 en su pared lateral. Una trombosis del seno cavernoso o un aneurisma de la carótida puede paralizar los nervios oculomotores."},
        {"id":"cf_012","concepto":"neuralgia trigémino","enunciado":"La neuralgia del trigémino (tic douloureux) afecta con más frecuencia a la rama:","opciones":{"A":"V1 (oftálmica)","B":"V2 (maxilar)","C":"V3 (mandibular)","D":"V2 y V3 por igual"},"correcta":"D","exp":"La neuralgia del trigémino afecta más frecuentemente a V2 (maxilar) y V3 (mandibular), raramente V1. Dolor lancinante unilateral en hemicara de segundos de duración, desencadenado por estímulos táctiles (comer, hablar, lavarse). Tratamiento: carbamazepina (1ª línea) o cirugía (descompresión microvascular de Jannetta)."},
        {"id":"cf_013","concepto":"foramen lacerum","enunciado":"¿Qué estructura importante pasa sobre el foramen lacerum?","opciones":{"A":"Arteria meníngea media","B":"Arteria carótida interna","C":"Vena yugular interna","D":"Nervio facial"},"correcta":"B","exp":"El foramen lacerum está ocluido en vida por fibrocartílago. La arteria carótida interna pasa sobre él (no a través) en su segmento petroso. El nervio petroso mayor sí pasa a través del foramen lacerum para llegar al ganglio pterigopalatino. En la base del cráneo la carótida recorre el canal carotídeo del temporal."},
        {"id":"cf_014","concepto":"parálisis facial central vs periférica","enunciado":"Un paciente con ictus hemisférico izquierdo presenta paresia facial. ¿Cómo será la paresia?","opciones":{"A":"Hemicara derecha completa incluyendo frente","B":"Hemicara derecha solo en su mitad inferior","C":"Hemicara izquierda completa","D":"Hemicara izquierda solo en su mitad inferior"},"correcta":"B","exp":"La parálisis central del VII (ictus hemisférico izquierdo) afecta la hemicara CONTRALATERAL (derecha) solo en la MITAD INFERIOR (músculo buccinador, orbicular de los labios). La frente se salva porque tiene representación bilateral en la corteza. La parálisis periférica (Bell) afecta TODA la hemicara ipsilateral incluyendo la frente."},
        {"id":"cf_015","concepto":"síndrome ángulo pontocerebeloso","enunciado":"Un schwannoma del nervio vestibular (VIII) en el ángulo pontocerebeloso comprime también el nervio:","opciones":{"A":"V (trigémino)","B":"VII (facial)","C":"IX (glosofaríngeo)","D":"VI (abducens)"},"correcta":"B","exp":"El schwannoma vestibular (mal llamado 'neurinoma del acústico') crece en el meato auditivo interno donde el VII y el VIII van juntos. Al crecer, comprime el VII produciendo paresia facial progresiva. Si sigue creciendo afecta el V (hipoestesia facial) y el cerebelo. Los síntomas iniciales son hipoacusia neurosensorial unilateral y acúfenos."},
    ],
    "nervios_craneales": [
        {"id":"nc_011","concepto":"oftalmoplejia internuclear","enunciado":"Un paciente no puede aducir el ojo derecho al mirar hacia la izquierda, pero sí converge. ¿Dónde está la lesión?","opciones":{"A":"Nervio oculomotor (III) derecho","B":"Fascículo longitudinal medial (FLM) derecho","C":"Nervio abducens (VI) izquierdo","D":"Nervio troclear (IV) derecho"},"correcta":"B","exp":"La oftalmoplejia internuclear (OIN) se debe a lesión del fascículo longitudinal medial (FLM). La OIN derecha lesiona el FLM DERECHO: el ojo derecho no aduce (no sigue al izquierdo) pero sí converge (porque el núcleo del III está intacto). En jóvenes: esclerosis múltiple. En ancianos: ictus del tronco."},
        {"id":"nc_012","concepto":"síndrome de Horner","enunciado":"El síndrome de Horner (ptosis + miosis + anhidrosis) es causado por lesión de:","opciones":{"A":"El nervio oculomotor (III)","B":"La vía simpática oculopupilar","C":"El nervio troclear (IV)","D":"El nervio óptico (II)"},"correcta":"B","exp":"El síndrome de Horner se debe a interrupción de la VÍA SIMPÁTICA: 1ª neurona (hipotálamo→médula C8-T1), 2ª neurona (ganglio estrellado→arteria carótida), 3ª neurona (plexo pericarotídeo→ojo). Causas: tumor de Pancoast (C8-T1), disección carotídea, siringomielia. La parálisis del III produce ptosis + midriasis + ojo hacia abajo y afuera."},
        {"id":"nc_013","concepto":"schwannoma vestibular","enunciado":"El primer síntoma más frecuente de un schwannoma vestibular (neurinoma del acústico) es:","opciones":{"A":"Parálisis facial","B":"Hipoacusia neurosensorial unilateral progresiva","C":"Vértigo episódico","D":"Cefalea"},"correcta":"B","exp":"El schwannoma vestibular debuta típicamente con HIPOACUSIA NEUROSENSORIAL UNILATERAL progresiva + acúfenos unilaterales. El vértigo es menos frecuente (paradójicamente, a pesar de nacer del nervio vestibular). La parálisis facial es tardía. El diagnóstico es con RM con gadolinio. El 95% son unilaterales y esporádicos."},
        {"id":"nc_014","concepto":"parálisis IV par","enunciado":"Un paciente con diplopía vertical que empeora al bajar escaleras y se inclina la cabeza hacia el hombro contralateral. ¿Qué nervio craneal está afectado?","opciones":{"A":"III (oculomotor)","B":"IV (troclear)","C":"VI (abducens)","D":"Nervio óptico (II)"},"correcta":"B","exp":"La parálisis del IV par (troclear) produce: diplopía VERTICAL que empeora al mirar hacia abajo y adentro (bajar escaleras, leer). El paciente INCLINA la cabeza hacia el hombro CONTRALATERAL para compensar (signo de la cabeza inclinada de Parks-Bielschowsky). Es el nervio craneal que más frecuentemente se lesiona en traumatismos craneales."},
        {"id":"nc_015","concepto":"síndrome bulbar vs pseudobulbar","enunciado":"La parálisis bulbar verdadera por lesión de los pares IX, X, XII produce:","opciones":{"A":"Disfagia, disartria, fasciculaciones linguales y reflejo nauseoso abolido","B":"Disfagia, disartria, risa y llanto espasmódico con reflejos exaltados","C":"Solo disfagia sin afectación del habla","D":"Parálisis facial y sordera"},"correcta":"A","exp":"Parálisis BULBAR (2ª motoneurona): disfagia, disartria, atrofia y fasciculaciones de la lengua, reflejo nauseoso ABOLIDO. Causas: ELA bulbar, siringobulbia, tumores del tronco. Parálisis PSEUDOBULBAR (1ª motoneurona bilateral): disfagia, disartria, RISA Y LLANTO ESPÁSTICOS, reflejos exaltados, sin atrofia. Causas: ictus bilateral, ELA."},
    ],
    "columna": [
        {"id":"col_011","concepto":"estenosis de canal","enunciado":"Paciente de 70 años con dolor lumbar y claudicación neurógena: camina 200m y debe parar por dolor en ambas piernas que cede al sentarse. La causa más probable es:","opciones":{"A":"Arteriopatía periférica (claudicación vascular)","B":"Hernia discal aguda","C":"Estenosis del canal lumbar","D":"Síndrome de la cola de caballo agudo"},"correcta":"C","exp":"La estenosis del canal lumbar produce claudicación NEURÓGENA: dolor/hormigueo en AMBAS piernas al caminar que cede al FLEXIONAR la columna (sentarse, inclinarse hacia adelante). Diferencia con claudicación VASCULAR: esta cede con el reposo sin necesidad de flexión y hay ausencia de pulsos. La hipertrofia del ligamento flavum y la artrosis de las facetas reducen el canal."},
        {"id":"col_012","concepto":"espondilolistesis","enunciado":"La espondilolistesis es el desplazamiento anterior de una vértebra sobre la inferior. El nivel más frecuentemente afectado es:","opciones":{"A":"L2-L3","B":"L3-L4","C":"L4-L5 o L5-S1","D":"T12-L1"},"correcta":"C","exp":"La espondilolistesis afecta más frecuentemente L4-L5 y L5-S1. Tipo ístmica (más frecuente en jóvenes): fractura de estrés del istmo (espondilólisis) + deslizamiento. Tipo degenerativa (más frecuente en adultos mayores): artrosis de las facetas. Síntomas: lumbalgia + ciática bilateral + posible estenosis de canal."},
        {"id":"col_013","concepto":"fractura de Chance","enunciado":"La fractura de Chance afecta a la columna lumbar por un mecanismo de:","opciones":{"A":"Compresión axial","B":"Hiperextensión brusca","C":"Hiperflexión por cinturón de seguridad en accidente","D":"Rotación pura"},"correcta":"C","exp":"La fractura de Chance (fractura en hebilla) es una fractura por HIPERFLEXIÓN + DISTRACCIÓN del cinturón de seguridad en accidentes de tráfico. Afecta las 3 columnas de Denis. Es inestable. Se asocia frecuentemente a lesiones viscerales abdominales (intestino, mesenterio) que hay que buscar siempre."},
        {"id":"col_014","concepto":"punción lumbar","enunciado":"Para realizar una punción lumbar de forma segura, ¿entre qué espacio se introduce la aguja?","opciones":{"A":"L1-L2","B":"L2-L3","C":"L3-L4 o L4-L5","D":"L5-S1"},"correcta":"C","exp":"La punción lumbar se realiza en L3-L4 o L4-L5 porque la médula espinal termina en L1-L2 en adultos (cono medular). La aguja entra en el espacio subaracnoideo donde solo están las raíces de la cola de caballo que se apartan sin lesionarse. Referencia: línea que une las crestas ilíacas = L4."},
        {"id":"col_015","concepto":"síndrome de Brown-Séquard","enunciado":"Una hemisección medular derecha (síndrome de Brown-Séquard) produce ipsilateralmente:","opciones":{"A":"Pérdida de dolor y temperatura","B":"Paresia y pérdida de sensibilidad propioceptiva y táctil fina","C":"Pérdida aislada del reflejo aquíleo","D":"Solo déficit motor sin sensitivo"},"correcta":"B","exp":"En el síndrome de Brown-Séquard (hemisección medular): IPSILATERAL = paresia (haz corticoespinal) + pérdida de propriocepción y tacto discriminativo (cordones posteriores). CONTRALATERAL = pérdida de dolor y temperatura (haz espinotalámico cruza 2 niveles sobre la entrada). Causas: traumatismo, tumor, esclerosis múltiple."},
    ],
    "atlas_axis": [
        {"id":"aa_011","concepto":"artritis reumatoide","enunciado":"¿Por qué la artritis reumatoide puede causar subluxación atlantoaxial peligrosa?","opciones":{"A":"Por calcificación del ligamento transverso","B":"Por destrucción sinovial del ligamento transverso del atlas y las articulaciones C1-C2","C":"Por fusión ósea de C1-C2","D":"Por fractura de la apófisis odontoides"},"correcta":"B","exp":"La artritis reumatoide destruye el tejido sinovial → destrucción del ligamento transverso del atlas y las articulaciones atlantoaxiales → subluxación anterior del atlas (C1 se desplaza hacia adelante sobre C2) → compresión del bulbo raquídeo. Riesgo especialmente en intubación/extensión del cuello. La distancia atlanto-odontoidea > 3mm es patológica."},
        {"id":"aa_012","concepto":"síndrome de Down","enunciado":"Los pacientes con síndrome de Down tienen mayor riesgo de inestabilidad atlantoaxial porque:","opciones":{"A":"Tienen vértebras cervicales fusionadas","B":"Presentan hiperlaxitud ligamentosa que debilita el ligamento transverso","C":"El foramen magno es más pequeño","D":"Tienen aplasia de la apófisis odontoides"},"correcta":"B","exp":"El síndrome de Down presenta hiperlaxitud ligamentosa generalizada por el defecto del colágeno. La laxitud del ligamento transverso del atlas permite inestabilidad atlantoaxial en el 10-20% de los pacientes con Down. Por eso se evalúa radiológicamente antes de actividades de riesgo (gimnasia, natación de competición)."},
        {"id":"aa_013","concepto":"bloqueo vertebral","enunciado":"El síndrome de Klippel-Feil consiste en:","opciones":{"A":"Fractura bilateral del istmo del axis","B":"Fusión congénita de dos o más vértebras cervicales con cuello corto y limitación de movimientos","C":"Agenesia del atlas","D":"Subluxación atlantoaxial traumática"},"correcta":"B","exp":"El síndrome de Klippel-Feil es una fusión CONGÉNITA de dos o más vértebras cervicales. La triada clásica: cuello corto, línea de implantación del cabello baja y limitación de movimientos cervicales. Se asocia a escoliosis, malformaciones renales y cardíacas. Las vértebras más frecuentemente fusionadas son C2-C3."},
        {"id":"aa_014","concepto":"tortícolis","enunciado":"Una tortícolis congénita (cabeza inclinada hacia un lado con rotación al lado contrario) se debe frecuentemente a:","opciones":{"A":"Subluxación atlantoaxial","B":"Fibrosis del músculo esternocleidomastoideo","C":"Fractura de la apófisis odontoides","D":"Bloqueo de las articulaciones facetarias cervicales"},"correcta":"B","exp":"La tortícolis muscular congénita se debe a fibrosis del músculo esternocleidomastoideo (SCM), probablemente por traumatismo del parto o isquemia. La cabeza se inclina hacia el lado del SCM acortado y rota al lado contrario. Tratamiento: fisioterapia precoz (estiramiento). Si no se corrige antes de los 2 años, puede requerir cirugía."},
        {"id":"aa_015","concepto":"vértebras cervicales","enunciado":"¿Cuál es la característica que tienen TODAS las vértebras cervicales que las distingue de las demás?","opciones":{"A":"La presencia de apófisis espinosa bífida","B":"El foramen transverso (agujero transverso) por donde pasan las arterias vertebrales","C":"La ausencia de cuerpo vertebral","D":"La presencia de carillas articulares para las costillas"},"correcta":"B","exp":"TODAS las vértebras cervicales (C1-C7) tienen FORAMEN TRANSVERSO (agujero en las apófisis transversas) por donde pasan las arterias vertebrales (de C6 a C1). Las vértebras torácicas tienen carillas costales. Las lumbares no tienen foramen transverso. Las apófisis espinosas bífidas son de C2-C6, no C7."},
    ],
    "carpo_tarso": [
        {"id":"ct_008","concepto":"necrosis navicular","enunciado":"La enfermedad de Köhler es una necrosis avascular del hueso navicular del tarso que afecta principalmente a:","opciones":{"A":"Adultos mayores","B":"Niños de 3-7 años, predominantemente varones","C":"Adolescentes deportistas","D":"Adultos con artritis reumatoide"},"correcta":"B","exp":"La enfermedad de Köhler es una osteocondritis del navicular del tarso que afecta a niños de 3-7 años (más en varones). Produce dolor en el mediopié y cojera. Rx: navicular aplanado y esclerótico. Tratamiento: plantillas de descarga. Pronóstico excelente, se reconstruye solo."},
        {"id":"ct_009","concepto":"síndrome túnel carpiano diagnóstico","enunciado":"¿Cuál es la prueba diagnóstica de confirmación para el síndrome del túnel carpiano?","opciones":{"A":"Radiografía de muñeca","B":"Electromiografía y estudio de conducción nerviosa","C":"Ecografía del canal carpiano","D":"Resonancia magnética"},"correcta":"B","exp":"El diagnóstico de confirmación del síndrome del túnel carpiano es la ELECTROMIOGRAFÍA (EMG) + estudios de CONDUCCIÓN NERVIOSA: demuestran enlentecimiento de la conducción del nervio mediano a nivel de la muñeca. La clínica (Tinel, Phalen, hormigueo nocturno) orienta pero la EMG confirma y cuantifica la gravedad."},
        {"id":"ct_010","concepto":"tarso coalición","enunciado":"La coalición tarsal (fusión de dos huesos del tarso) más frecuente es entre:","opciones":{"A":"Astrágalo-navicular","B":"Calcáneo-cuboides","C":"Calcáneo-navicular o astrágalo-calcáneo","D":"Cuneiforme-navicular"},"correcta":"C","exp":"Las coaliciones tarsales más frecuentes son: calcáneo-navicular (50%) y astrágalo-calcáneo (talocalcánea, 25%). Producen pie plano rígido doloroso en adolescentes. La restricción del movimiento subtalar es característica. Tratamiento: inicialmente conservador, cirugía si fracasa (resección de la barra)."},
    ],
    "ligamentos_columna": [
        {"id":"lc_008","concepto":"clasificación inestabilidad","enunciado":"Según Denis, ¿cuál es la columna más importante para determinar la estabilidad de una fractura vertebral?","opciones":{"A":"Columna anterior","B":"Columna media","C":"Columna posterior","D":"Las tres columnas por igual"},"correcta":"B","exp":"La columna MEDIA de Denis (mitad posterior del cuerpo + LLP + pared posterior del disco) es la más importante para la estabilidad. Si la columna media está intacta, la fractura generalmente es estable. Si está lesionada, es potencialmente inestable. La fractura con lesión de 2 o 3 columnas es inestable."},
        {"id":"lc_009","concepto":"articulaciones facetarias","enunciado":"Las articulaciones facetarias (interapofisarias) de la columna lumbar están orientadas en un plano sagital para:","opciones":{"A":"Permitir la rotación axial","B":"Limitar la rotación y permitir la flexoextensión y la lateralización","C":"Permitir la flexión lateral exclusivamente","D":"Limitar la flexoextensión"},"correcta":"B","exp":"Las facetas lumbares están en plano SAGITAL → limitan la rotación axial (por eso las torsiones bruscan lesionan los discos lumbares) y permiten la flexoextensión y lateralización. Las facetas cervicales son oblicuas → permiten flexión, extensión, rotación y lateralización. Las torácicas son frontales → permiten rotación pero limitan la flexión."},
    ],
    "disco_intervertebral": [
        {"id":"di_006","concepto":"hernia discal cervical","enunciado":"Una hernia discal cervical C5-C6 comprime la raíz nerviosa:","opciones":{"A":"C5","B":"C6","C":"C7","D":"C8"},"correcta":"B","exp":"En la columna cervical, la hernia discal C5-C6 comprime la raíz C6 (la raíz que sale por el foramen de C6, bajo el pedículo de C6). Síntomas de C6: dolor en cara lateral del brazo, antebrazo y dedo pulgar; parestesias en pulgar e índice; debilidad del bíceps (flexión del codo); pérdida del reflejo bicipital."},
        {"id":"di_007","concepto":"dolor referido discal","enunciado":"El dolor lumbar que baja por el nervio ciático (ciática) se denomina:","opciones":{"A":"Lumbalgia mecánica","B":"Radiculopatía o síndrome ciático","C":"Estenosis de canal","D":"Claudicación neurógena"},"correcta":"B","exp":"La radiculopatía ciática (ciática) es el dolor que sigue el trayecto del nervio ciático desde la región glútea por la cara posterior del muslo hasta la pierna y el pie. Suele deberse a hernia discal L4-L5 (raíz L5) o L5-S1 (raíz S1). Empeora con Valsalva (toser, defecar). El test de Lasègue (elevación de la pierna recta) es positivo."},
    ],
}

