    BANCO["carpo_tarso"]["preguntas"].append({"id": "carpo_tarso_auto_954d55b2", "concepto": "Fractura de escafoides y riesgo de necrosis avascular", "enunciado": "Un varón de 22 años acude a urgencias tras caída sobre la mano en hiperextensión, presentando dolor a la palpación en la tabaquera anatómica. Se confirma fractura del escafoides en su tercio proximal. ¿Cuál es la complicación más característica de esta localización?", "opciones": {"A": "Síndrome del túnel carpiano agudo por compresión del nervio mediano", "B": "Necrosis avascular del fragmento proximal por vascularización retrógrada desde la rama dorsal de la arteria radial", "C": "Lesión del nervio cubital en el canal de Guyon", "D": "Pseudoartrosis del semilunar por afectación del ligamento escafolunar"}, "correcta": "B", "exp": "El escafoides recibe su irrigación principalmente de ramas dorsales de la arteria radial que penetran distalmente, por lo que una fractura proximal interrumpe el flujo retrógrado y produce necrosis avascular del fragmento proximal."})
