if "articulacion_codo" in BANCO and not any(q["enunciado"] == "Una niña de 3 años llega a urgencias con el brazo en extensión y pronación tras haber sido levantada bruscamente de la mano (pronación dolorosa o codo de niñera). ¿Qué estructura está implicada en esta lesión?" for q in BANCO["articulacion_codo"]["preguntas"]):
    BANCO["articulacion_codo"]["preguntas"].append({"id": "articulacion_codo_auto_d6e80ceb", "concepto": "ligamento anular cabeza radial", "enunciado": "Una niña de 3 años llega a urgencias con el brazo en extensión y pronación tras haber sido levantada bruscamente de la mano (pronación dolorosa o codo de niñera). ¿Qué estructura está implicada en esta lesión?", "opciones": {"A": "Subluxación de la cabeza radial bajo el ligamento anular", "B": "Rotura del ligamento colateral cubital", "C": "Luxación posterior de la articulación humerocubital", "D": "Fractura supracondílea del húmero"}, "correcta": "A", "exp": "La pronación dolorosa se debe a la subluxación de la cabeza del radio a través del ligamento anular, que en niños es más laxo y permite el deslizamiento distal del radio. La reducción se realiza mediante supinación y flexión del codo con presión sobre la cabeza radial."})

