    BANCO["atlas_axis"]["preguntas"].append({"id": "atlas_axis_auto_2902b84f", "concepto": "articulación atlantoaxoidea media", "enunciado": "La articulación atlantoaxoidea media, responsable principalmente del movimiento de rotación de la cabeza ('decir no'), se establece entre la apófisis odontoides del axis y:", "opciones": {"A": "Las masas laterales del atlas", "B": "El arco posterior del atlas y el ligamento amarillo", "C": "La fóvea dental del arco anterior del atlas y el ligamento transverso", "D": "El cóndilo occipital y la membrana tectoria"}, "correcta": "C", "exp": "La articulación atlantoaxoidea media es una trocoide (pivote) formada por la odontosis del axis articulando anteriormente con la fóvea dental del arco anterior del atlas y posteriormente con el ligamento transverso del atlas. Permite aproximadamente el 50% de la rotación cervical total."})

