if "arterias_ms_mi" in BANCO and not any(q["enunciado"] == "Un paciente sufre una luxación anterior de hombro y posteriormente presenta isquemia del miembro superior. La arteriografía muestra lesión de la arteria axilar en su segundo segmento. ¿Qué estructura anatómica define este segmento y qué rama se origina en él?" for q in BANCO["arterias_ms_mi"]["preguntas"]):
    BANCO["arterias_ms_mi"]["preguntas"].append({"id": "arterias_ms_mi_auto_a7c732b4", "concepto": "arteria axilar segmentos", "enunciado": "Un paciente sufre una luxación anterior de hombro y posteriormente presenta isquemia del miembro superior. La arteriografía muestra lesión de la arteria axilar en su segundo segmento. ¿Qué estructura anatómica define este segmento y qué rama se origina en él?", "opciones": {"A": "Posterior al músculo pectoral menor; origina la arteria toracoacromial", "B": "Posterior al músculo pectoral menor; origina la arteria torácica lateral", "C": "Superior al músculo pectoral menor; origina la arteria torácica superior", "D": "Inferior al músculo pectoral menor; origina las arterias circunflejas humerales"}, "correcta": "B", "exp": "La arteria axilar se divide en tres segmentos según su relación con el pectoral menor: el segundo segmento queda posterior a este músculo y origina la arteria torácica lateral (y a veces la toracoacromial). Regla mnemotécnica: el número de ramas coincide con el número de segmento (1-2-3)."})
if "arterias_ms_mi" in BANCO and not any(q["enunciado"] == "Antes de realizar una punción de la arteria radial para gasometría arterial, se efectúa el test de Allen. ¿Qué estructura anatómica se está evaluando con esta maniobra?" for q in BANCO["arterias_ms_mi"]["preguntas"]):
    BANCO["arterias_ms_mi"]["preguntas"].append({"id": "arterias_ms_mi_auto_8ca35ab3", "concepto": "test de Allen", "enunciado": "Antes de realizar una punción de la arteria radial para gasometría arterial, se efectúa el test de Allen. ¿Qué estructura anatómica se está evaluando con esta maniobra?", "opciones": {"A": "La permeabilidad del arco palmar profundo formado principalmente por la arteria radial", "B": "La permeabilidad del arco palmar superficial formado principalmente por la arteria cubital", "C": "La integridad de la arteria interósea anterior como suplencia", "D": "La dominancia de la arteria mediana persistente"}, "correcta": "B", "exp": "El test de Allen evalúa la circulación colateral de la mano, comprobando que la arteria cubital (principal contribuyente al arco palmar superficial) sea capaz de irrigar toda la mano si se ocluye la radial. La arteria radial contribuye principalmente al arco palmar profundo."})

# AUTO 2026-05-16 — musculos_mi
if "musculos_mi" in BANCO and not any(q["enunciado"] == "Un paciente sufre una fractura del cuello del peroné tras un traumatismo lateral en la rodilla. A la exploración presenta imposibilidad para la dorsiflexión y eversión del pie, con marcha en steppage. ¿Qué músculo conserva su función al estar inervado por un nervio diferente al lesionado?" for q in BANCO["musculos_mi"]["preguntas"]):
    BANCO["musculos_mi"]["preguntas"].append({"id": "musculos_mi_auto_cfd64e4c", "concepto": "lesión nervio ciático poplíteo externo", "enunciado": "Un paciente sufre una fractura del cuello del peroné tras un traumatismo lateral en la rodilla. A la exploración presenta imposibilidad para la dorsiflexión y eversión del pie, con marcha en steppage. ¿Qué músculo conserva su función al estar inervado por un nervio diferente al lesionado?", "opciones": {"A": "Tibial anterior", "B": "Peroneo largo", "C": "Tibial posterior", "D": "Extensor largo de los dedos"}, "correcta": "C", "exp": "El tibial posterior está inervado por el nervio tibial (rama del ciático), mientras que la lesión del nervio peroneo común en el cuello del peroné paraliza los compartimentos anterior (peroneo profundo) y lateral (peroneo superficial). El tibial posterior produce inversión y flexión plantar, que se conservan."})
if "musculos_mi" in BANCO and not any(q["enunciado"] == "Una corredora de fondo presenta dolor en la cara medial de la rodilla, unos 5 cm por debajo de la interlínea articular, donde se palpa una zona dolorosa correspondiente a la inserción común de los tendones de la pata de ganso. ¿Qué tres músculos forman esta estructura?" for q in BANCO["musculos_mi"]["preguntas"]):
    BANCO["musculos_mi"]["preguntas"].append({"id": "musculos_mi_auto_e23a5be1", "concepto": "pata de ganso superficial", "enunciado": "Una corredora de fondo presenta dolor en la cara medial de la rodilla, unos 5 cm por debajo de la interlínea articular, donde se palpa una zona dolorosa correspondiente a la inserción común de los tendones de la pata de ganso. ¿Qué tres músculos forman esta estructura?", "opciones": {"A": "Sartorio, recto interno (grácil) y semitendinoso", "B": "Sartorio, semimembranoso y semitendinoso", "C": "Recto interno, semitendinoso y semimembranoso", "D": "Sartorio, recto interno y semimembranoso"}, "correcta": "A", "exp": "La pata de ganso superficial (pes anserinus) está formada por los tendones del sartorio (n. femoral), grácil/recto interno (n. obturador) y semitendinoso (n. ciático), que se insertan en la cara medial de la tibia. Regla mnemotécnica: 'Say Grace before Tea' (Sartorius, Gracilis, semiTendinosus)."})

# AUTO 2026-05-16 — disco_intervertebral
if "disco_intervertebral" in BANCO and not any(q["enunciado"] == "Un paciente de 45 años presenta lumbalgia irradiada por cara lateral del muslo y pierna hasta el dorso del pie, con debilidad para la dorsiflexión del primer dedo e hipoestesia en el primer espacio interdigital. La RM muestra una hernia discal posterolateral L4-L5. ¿Qué raíz nerviosa está comprimida y por qué motivo anatómico?" for q in BANCO["disco_intervertebral"]["preguntas"]):
    BANCO["disco_intervertebral"]["preguntas"].append({"id": "disco_intervertebral_auto_4d37ce3b", "concepto": "hernia discal lumbar L4-L5", "enunciado": "Un paciente de 45 años presenta lumbalgia irradiada por cara lateral del muslo y pierna hasta el dorso del pie, con debilidad para la dorsiflexión del primer dedo e hipoestesia en el primer espacio interdigital. La RM muestra una hernia discal posterolateral L4-L5. ¿Qué raíz nerviosa está comprimida y por qué motivo anatómico?", "opciones": {"A": "Raíz L4, porque la hernia posterolateral comprime la raíz que sale por el agujero de conjunción del mismo nivel", "B": "Raíz L5, porque la hernia posterolateral comprime la raíz que desciende para salir por el agujero inferior", "C": "Raíz S1, porque las hernias lumbares siempre afectan a la raíz dos niveles inferiores", "D": "Raíz L5, porque la hernia comprime la raíz a su salida por el agujero de conjunción L4-L5"}, "correcta": "B", "exp": "En las hernias posterolaterales lumbares (las más frecuentes), se comprime la raíz que desciende (raíz transitoria), no la que sale por ese agujero; por tanto, una hernia L4-L5 afecta a la raíz L5. La raíz L4 ya ha salido por encima del disco herniado y queda preservada."})
if "disco_intervertebral" in BANCO and not any(q["enunciado"] == "Respecto a la composición y origen embriológico del disco intervertebral, ¿cuál de las siguientes afirmaciones es CORRECTA?" for q in BANCO["disco_intervertebral"]["preguntas"]):
    BANCO["disco_intervertebral"]["preguntas"].append({"id": "disco_intervertebral_auto_ebd35ed2", "concepto": "núcleo pulposo embriología", "enunciado": "Respecto a la composición y origen embriológico del disco intervertebral, ¿cuál de las siguientes afirmaciones es CORRECTA?", "opciones": {"A": "El anillo fibroso deriva de la notocorda y está formado por fibras de colágeno tipo II dispuestas concéntricamente", "B": "El núcleo pulposo deriva de la notocorda y es un tejido gelatinoso rico en proteoglicanos y colágeno tipo II", "C": "Tanto el anillo fibroso como el núcleo pulposo derivan del esclerotomo y contienen colágeno tipo I exclusivamente", "D": "El núcleo pulposo deriva del miotomo y pierde toda su vascularización tras el nacimiento"}, "correcta": "B", "exp": "El núcleo pulposo es el único derivado adulto persistente de la notocorda, con alto contenido en agua, proteoglicanos (agrecano) y colágeno tipo II. El anillo fibroso, en cambio, deriva del esclerotomo y está formado por láminas concéntricas de colágeno tipo I."})

