if "huesos_ms" in BANCO and not any(q["enunciado"] == "Un varón de 35 años acude a urgencias tras un accidente de moto con fractura espiroidea del tercio medio del húmero. En la exploración presenta incapacidad para la extensión de la muñeca y los dedos (mano caída), con anestesia en el dorso del primer espacio interóseo. ¿Qué estructura anatómica se ha lesionado y en qué relación se encuentra con el hueso?" for q in BANCO["huesos_ms"]["preguntas"]):
    BANCO["huesos_ms"]["preguntas"].append({"id": "huesos_ms_auto_41b49d3b", "concepto": "fractura húmero diáfisis", "enunciado": "Un varón de 35 años acude a urgencias tras un accidente de moto con fractura espiroidea del tercio medio del húmero. En la exploración presenta incapacidad para la extensión de la muñeca y los dedos (mano caída), con anestesia en el dorso del primer espacio interóseo. ¿Qué estructura anatómica se ha lesionado y en qué relación se encuentra con el hueso?", "opciones": {"A": "Nervio mediano, que discurre por el canal bicipital medial", "B": "Nervio radial, que recorre el surco radial (canal de torsión) en la cara posterior del húmero", "C": "Nervio cubital, que pasa por el surco del nervio cubital en el epicóndilo medial", "D": "Nervio axilar, que rodea el cuello quirúrgico del húmero"}, "correcta": "B", "exp": "El nervio radial discurre por el surco radial (canal de torsión) en la cara posterior de la diáfisis humeral, siendo vulnerable en fracturas del tercio medio y produciendo la clásica 'mano caída'. El nervio axilar se lesiona en fracturas del cuello quirúrgico, no de la diáfisis."})
if "huesos_ms" in BANCO and not any(q["enunciado"] == "Un joven de 22 años cae sobre la mano en extensión y presenta dolor en la tabaquera anatómica. La radiografía inicial es normal, pero a las 3 semanas se confirma fractura del polo proximal del escafoides con necrosis avascular. ¿Cuál es la base anatómica de esta complicación?" for q in BANCO["huesos_ms"]["preguntas"]):
    BANCO["huesos_ms"]["preguntas"].append({"id": "huesos_ms_auto_da72b18f", "concepto": "fractura escafoides", "enunciado": "Un joven de 22 años cae sobre la mano en extensión y presenta dolor en la tabaquera anatómica. La radiografía inicial es normal, pero a las 3 semanas se confirma fractura del polo proximal del escafoides con necrosis avascular. ¿Cuál es la base anatómica de esta complicación?", "opciones": {"A": "El escafoides recibe su irrigación principal de ramas distales de la arteria radial, que entran por el polo distal, por lo que el polo proximal queda mal vascularizado", "B": "El escafoides es un hueso intraarticular sin periostio, por lo que no recibe vascularización", "C": "La arteria interósea anterior irriga exclusivamente el polo proximal, y se lesiona siempre en la fractura", "D": "El escafoides recibe su vascularización del ligamento escafolunar, que se rompe en la fractura"}, "correcta": "A", "exp": "La irrigación del escafoides depende de ramas de la arteria radial que penetran por el polo distal y avanzan retrógradamente, dejando el polo proximal especialmente vulnerable a necrosis avascular tras fractura. Por ello, las fracturas proximales tienen peor pronóstico y mayor tasa de pseudoartrosis."})

