    BANCO["huesos_mi"]["preguntas"].append({"id": "huesos_mi_auto_3d842cdf", "concepto": "lesión nervio peroneo común", "enunciado": "Un paciente con escayola apretada en la pierna desarrolla, tras retirarla, imposibilidad para la dorsiflexión del pie y caída del antepié (pie equino), con hipoestesia en el dorso del pie y primer espacio interdigital. ¿Qué estructura ósea es la responsable de la localización superficial y vulnerabilidad del nervio lesionado?", "opciones": {"A": "Maléolo medial de la tibia", "B": "Cabeza del peroné (fíbula)", "C": "Tuberosidad anterior de la tibia", "D": "Cóndilo medial del fémur"}, "correcta": "B", "exp": "El nervio peroneo (fibular) común rodea el cuello de la fíbula justo distal a su cabeza, donde es muy superficial y vulnerable a compresiones por yesos, cruce de piernas o traumatismos. Su lesión produce pie caído por parálisis de los compartimentos anterior y lateral de la pierna."})

