if "rodilla" in BANCO and not any(q["enunciado"] == "Un futbolista recibe un golpe lateral en la rodilla con el pie fijo en el suelo, produciéndose un valgo forzado con rotación externa de la tibia. La RMN muestra la clásica 'tríada infeliz'. ¿Qué tres estructuras están lesionadas?" for q in BANCO["rodilla"]["preguntas"]):
    BANCO["rodilla"]["preguntas"].append({"id": "rodilla_auto_f7a4ebac", "concepto": "tríada infeliz de O'Donoghue", "enunciado": "Un futbolista recibe un golpe lateral en la rodilla con el pie fijo en el suelo, produciéndose un valgo forzado con rotación externa de la tibia. La RMN muestra la clásica 'tríada infeliz'. ¿Qué tres estructuras están lesionadas?", "opciones": {"A": "Ligamento cruzado posterior, ligamento colateral lateral y menisco lateral", "B": "Ligamento cruzado anterior, ligamento colateral medial y menisco medial", "C": "Ligamento cruzado anterior, ligamento colateral lateral y menisco lateral", "D": "Ligamento cruzado anterior, ligamento colateral medial y menisco lateral"}, "correcta": "B", "exp": "La tríada infeliz de O'Donoghue clásica incluye LCA, LCM y menisco medial, dado que el menisco medial está firmemente unido al ligamento colateral medial a través de su inserción capsular. El menisco lateral, en cambio, es más móvil al no estar fijado al colateral lateral (separado por el tendón del poplíteo)."})
if "rodilla" in BANCO and not any(q["enunciado"] == "Respecto a la vascularización de los meniscos de la rodilla, ¿cuál de las siguientes afirmaciones es correcta y explica el pronóstico de reparación de las lesiones meniscales?" for q in BANCO["rodilla"]["preguntas"]):
    BANCO["rodilla"]["preguntas"].append({"id": "rodilla_auto_03012bd2", "concepto": "irrigación meniscal", "enunciado": "Respecto a la vascularización de los meniscos de la rodilla, ¿cuál de las siguientes afirmaciones es correcta y explica el pronóstico de reparación de las lesiones meniscales?", "opciones": {"A": "Toda la superficie meniscal está vascularizada por la arteria geniculada media, por lo que cualquier rotura cicatriza espontáneamente", "B": "Los meniscos son completamente avasculares en el adulto, por lo que ninguna lesión meniscal puede repararse quirúrgicamente con éxito", "C": "Solo el tercio periférico (zona roja-roja) está vascularizado por las arterias geniculadas, mientras que los dos tercios internos (zona blanca) son avasculares y se nutren por difusión del líquido sinovial", "D": "El menisco lateral está completamente vascularizado, mientras que el medial es totalmente avascular"}, "correcta": "C", "exp": "Solo el tercio periférico meniscal (zona roja-roja) recibe irrigación de las arterias geniculadas medial y lateral inferiores procedentes de la poplítea; los 2/3 internos (zona blanca-blanca) se nutren por difusión sinovial. Por ello, solo las roturas periféricas tienen capacidad de cicatrización y son susceptibles de sutura meniscal."})

