if "articulacion_codo" in BANCO and not any(q["enunciado"] == "Un niño de 8 años sufre una caída sobre la mano en extensión y acude con el codo en semiflexión, deformidad posterior y dolor intenso. Tras la reducción de la luxación posterior de codo, presenta incapacidad para la flexión de las articulaciones interfalángicas del 4º y 5º dedos, así como hipoestesia en el borde cubital de la mano. ¿Qué nervio se ha lesionado y dónde?" for q in BANCO["articulacion_codo"]["preguntas"]):
    BANCO["articulacion_codo"]["preguntas"].append({"id": "articulacion_codo_auto_8875968c", "concepto": "luxación posterior codo", "enunciado": "Un niño de 8 años sufre una caída sobre la mano en extensión y acude con el codo en semiflexión, deformidad posterior y dolor intenso. Tras la reducción de la luxación posterior de codo, presenta incapacidad para la flexión de las articulaciones interfalángicas del 4º y 5º dedos, así como hipoestesia en el borde cubital de la mano. ¿Qué nervio se ha lesionado y dónde?", "opciones": {"A": "Nervio mediano a nivel de la fosa cubital", "B": "Nervio cubital en el surco epitrocleo-olecraniano", "C": "Nervio radial en el canal de torsión humeral", "D": "Nervio interóseo anterior en la membrana interósea"}, "correcta": "B", "exp": "El nervio cubital discurre por el surco epitrocleo-olecraniano (entre epitróclea y olécranon), siendo el más vulnerable en las luxaciones posteriores de codo y fracturas de epitróclea. Inerva el flexor profundo de los dedos para el 4º-5º dedos y la sensibilidad cubital de la mano."})
if "articulacion_codo" in BANCO and not any(q["enunciado"] == "Un padre acude a urgencias con su hija de 3 años a la que tiró del brazo bruscamente al cruzar la calle. La niña mantiene el codo en extensión y pronación, llorando y rehusando moverlo (pronación dolorosa o codo de niñera). ¿Cuál es el mecanismo lesional preciso?" for q in BANCO["articulacion_codo"]["preguntas"]):
    BANCO["articulacion_codo"]["preguntas"].append({"id": "articulacion_codo_auto_c72cf526", "concepto": "ligamento anular del radio", "enunciado": "Un padre acude a urgencias con su hija de 3 años a la que tiró del brazo bruscamente al cruzar la calle. La niña mantiene el codo en extensión y pronación, llorando y rehusando moverlo (pronación dolorosa o codo de niñera). ¿Cuál es el mecanismo lesional preciso?", "opciones": {"A": "Luxación posterior de la cabeza del radio respecto al cóndilo humeral", "B": "Rotura completa del ligamento colateral cubital con inestabilidad en valgo", "C": "Subluxación de la cabeza del radio con deslizamiento distal del ligamento anular", "D": "Fractura en tallo verde de la apófisis coronoides del cúbito"}, "correcta": "C", "exp": "En el codo de niñera, la tracción axial sobre el antebrazo en pronación provoca que la cabeza del radio se deslice parcialmente por debajo del ligamento anular, que en niños es laxo y delgado. La reducción se logra con supinación y flexión del codo."})

