if "nervios_craneales" in BANCO and not any(q["enunciado"] == "Durante una cirugía de base de cráneo se aborda el foramen yugular. ¿Qué combinación de nervios craneales atraviesa esta estructura y cuál sería el déficit clínico esperable tras su lesión?" for q in BANCO["nervios_craneales"]["preguntas"]):
    BANCO["nervios_craneales"]["preguntas"].append({"id": "nervios_craneales_auto_15c10abf", "concepto": "forámenes base craneal", "enunciado": "Durante una cirugía de base de cráneo se aborda el foramen yugular. ¿Qué combinación de nervios craneales atraviesa esta estructura y cuál sería el déficit clínico esperable tras su lesión?", "opciones": {"A": "V, VII y VIII - parálisis facial e hipoacusia", "B": "IX, X y XI - disfagia, disfonía y debilidad del trapecio/ECM", "C": "III, IV y VI - oftalmoplejía completa", "D": "X, XI y XII - disfonía y desviación lingual"}, "correcta": "B", "exp": "Por el foramen yugular pasan los pares IX (glosofaríngeo), X (vago) y XI (accesorio), junto con la vena yugular interna; su lesión conjunta produce el síndrome de Vernet con disfagia, disfonía, pérdida del reflejo nauseoso y debilidad del trapecio y esternocleidomastoideo. El XII par sale por el conducto del hipogloso, no por el foramen yugular."})

