if "ligamentos_columna" in BANCO and not any(q["enunciado"] == "Un varón de 50 años sufre un traumatismo cervical con hiperflexión brusca. La RM muestra una hernia discal posterior con compresión medular. ¿Qué ligamento, situado dentro del canal vertebral en la cara posterior de los cuerpos vertebrales, suele estar implicado en la contención inicial de este tipo de hernias y se debilita en su porción lateral favoreciendo las hernias posterolaterales?" for q in BANCO["ligamentos_columna"]["preguntas"]):
    BANCO["ligamentos_columna"]["preguntas"].append({"id": "ligamentos_columna_auto_63badca2", "concepto": "ligamento longitudinal posterior", "enunciado": "Un varón de 50 años sufre un traumatismo cervical con hiperflexión brusca. La RM muestra una hernia discal posterior con compresión medular. ¿Qué ligamento, situado dentro del canal vertebral en la cara posterior de los cuerpos vertebrales, suele estar implicado en la contención inicial de este tipo de hernias y se debilita en su porción lateral favoreciendo las hernias posterolaterales?", "opciones": {"A": "Ligamento longitudinal anterior", "B": "Ligamento longitudinal posterior", "C": "Ligamento amarillo (flavum)", "D": "Ligamento supraespinoso"}, "correcta": "B", "exp": "El ligamento longitudinal posterior recorre la cara posterior de los cuerpos vertebrales dentro del canal raquídeo; es más estrecho y débil lateralmente, lo que explica que las hernias discales sean típicamente posterolaterales. El longitudinal anterior limita la hiperextensión y el amarillo une las láminas."})
