if "huesos_mi" in BANCO and not any(q["enunciado"] == "Una mujer de 78 años sufre una caída casual con fractura subcapital desplazada del cuello femoral. El traumatólogo opta por una artroplastia y no por osteosíntesis. ¿Cuál es el fundamento anatómico principal de esta decisión?" for q in BANCO["huesos_mi"]["preguntas"]):
    BANCO["huesos_mi"]["preguntas"].append({"id": "huesos_mi_auto_5e63918e", "concepto": "fractura cuello femoral", "enunciado": "Una mujer de 78 años sufre una caída casual con fractura subcapital desplazada del cuello femoral. El traumatólogo opta por una artroplastia y no por osteosíntesis. ¿Cuál es el fundamento anatómico principal de esta decisión?", "opciones": {"A": "La cabeza femoral recibe su vascularización principal de la arteria del ligamento redondo, rama de la obturatriz", "B": "El aporte sanguíneo de la cabeza depende fundamentalmente de las arterias circunflejas femorales (sobre todo la medial), cuyas ramas retinaculares se rompen en fracturas desplazadas y producen necrosis avascular", "C": "El cuello femoral carece de periostio, por lo que nunca consolida tras una fractura", "D": "La arteria femoral profunda irriga directamente la cabeza femoral y suele lesionarse en estas fracturas"}, "correcta": "B", "exp": "La cabeza del fémur se vasculariza fundamentalmente por las ramas retinaculares de la arteria circunfleja femoral medial (rama de la femoral profunda); su rotura en fracturas subcapitales desplazadas produce necrosis avascular. La arteria del ligamento redondo aporta un flujo mínimo, insuficiente en el adulto."})
if "huesos_mi" in BANCO and not any(q["enunciado"] == "Un trabajador de 35 años cae desde un andamio de 4 metros aterrizando de pie. Presenta dolor intenso en el talón y la radiografía muestra fractura conminuta del calcáneo con disminución del ángulo de Böhler. ¿Qué otra lesión asociada debe descartarse de forma sistemática por el mecanismo lesional?" for q in BANCO["huesos_mi"]["preguntas"]):
    BANCO["huesos_mi"]["preguntas"].append({"id": "huesos_mi_auto_5e17e0c4", "concepto": "fractura calcáneo", "enunciado": "Un trabajador de 35 años cae desde un andamio de 4 metros aterrizando de pie. Presenta dolor intenso en el talón y la radiografía muestra fractura conminuta del calcáneo con disminución del ángulo de Böhler. ¿Qué otra lesión asociada debe descartarse de forma sistemática por el mecanismo lesional?", "opciones": {"A": "Fractura de escafoides carpiano", "B": "Fractura por compresión de cuerpo vertebral toracolumbar", "C": "Luxación anterior de hombro", "D": "Fractura de Colles distal de radio"}, "correcta": "B", "exp": "Las caídas de altura sobre los pies transmiten la fuerza axial desde el calcáneo a través del eje del miembro inferior hasta la columna, asociándose hasta en un 10-15% de los casos a fracturas por compresión toracolumbares (especialmente T12-L2). Es obligado explorar y radiografiar la columna en toda fractura de calcáneo por caída."})

