if "musculos_ms" in BANCO and not any(q["enunciado"] == "Un varón de 45 años acude a urgencias tras dormirse con el brazo apoyado sobre el respaldo de un banco ('parálisis del sábado noche'). En la exploración presenta caída de la muñeca (mano péndula), imposibilidad para la extensión de los dedos y la muñeca, e hipoestesia en el dorso de la primera comisura. La flexo-extensión del codo está conservada. ¿A qué nivel se ha producido la compresión nerviosa?" for q in BANCO["musculos_ms"]["preguntas"]):
    BANCO["musculos_ms"]["preguntas"].append({"id": "musculos_ms_auto_d318cfca", "concepto": "lesión nervio radial humeral", "enunciado": "Un varón de 45 años acude a urgencias tras dormirse con el brazo apoyado sobre el respaldo de un banco ('parálisis del sábado noche'). En la exploración presenta caída de la muñeca (mano péndula), imposibilidad para la extensión de los dedos y la muñeca, e hipoestesia en el dorso de la primera comisura. La flexo-extensión del codo está conservada. ¿A qué nivel se ha producido la compresión nerviosa?", "opciones": {"A": "Nervio radial en la axila, antes de dar ramas para el tríceps", "B": "Nervio radial en el surco radial del húmero, tras dar ramas para el tríceps", "C": "Rama profunda del nervio radial al atravesar el supinador (síndrome del túnel radial)", "D": "Nervio mediano en el codo a nivel del pronador redondo"}, "correcta": "B", "exp": "La preservación de la extensión del codo (tríceps inervado proximalmente) y la afectación de extensores del antebrazo localiza la lesión en el surco radial humeral, distal a las ramas tricipitales. Es la presentación clásica de la 'parálisis del sábado noche'."})
if "musculos_ms" in BANCO and not any(q["enunciado"] == "Una mujer de 60 años con laceración profunda en la cara anterior de la muñeca presenta, tras la sutura, imposibilidad para realizar la oposición del pulgar y atrofia de la eminencia tenar, conservando la sensibilidad palmar. ¿Qué nervio se ha lesionado y qué músculo es responsable principal del movimiento perdido?" for q in BANCO["musculos_ms"]["preguntas"]):
    BANCO["musculos_ms"]["preguntas"].append({"id": "musculos_ms_auto_cafa8a93", "concepto": "inervación músculos intrínsecos mano", "enunciado": "Una mujer de 60 años con laceración profunda en la cara anterior de la muñeca presenta, tras la sutura, imposibilidad para realizar la oposición del pulgar y atrofia de la eminencia tenar, conservando la sensibilidad palmar. ¿Qué nervio se ha lesionado y qué músculo es responsable principal del movimiento perdido?", "opciones": {"A": "Rama recurrente del nervio mediano; músculo oponente del pulgar", "B": "Rama profunda del nervio cubital; músculo aductor del pulgar", "C": "Nervio interóseo anterior; músculo flexor largo del pulgar", "D": "Rama superficial del nervio radial; músculo extensor corto del pulgar"}, "correcta": "A", "exp": "La rama recurrente (motora) del nervio mediano inerva el oponente, abductor corto y fascículo superficial del flexor corto del pulgar; su lesión aislada produce atrofia tenar sin déficit sensitivo. El oponente del pulgar es el principal responsable de la oposición."})

