if "manguito_rotador" in BANCO and not any(q["enunciado"] == "Un paciente de 60 años presenta dolor en el hombro con arco doloroso entre 60° y 120° de abducción y signo de Jobe positivo. La ecografía confirma rotura tendinosa. ¿Cuál es el tendón del manguito rotador más frecuentemente lesionado y por qué razón anatómica?" for q in BANCO["manguito_rotador"]["preguntas"]):
    BANCO["manguito_rotador"]["preguntas"].append({"id": "manguito_rotador_auto_0a161be8", "concepto": "tendón más frecuentemente lesionado", "enunciado": "Un paciente de 60 años presenta dolor en el hombro con arco doloroso entre 60° y 120° de abducción y signo de Jobe positivo. La ecografía confirma rotura tendinosa. ¿Cuál es el tendón del manguito rotador más frecuentemente lesionado y por qué razón anatómica?", "opciones": {"A": "Subescapular, por su paso bajo la apófisis coracoides", "B": "Redondo menor, por su inserción en el troquíter", "C": "Supraespinoso, por su paso por el espacio subacromial y zona hipovascular crítica", "D": "Infraespinoso, por su tracción constante durante la rotación externa"}, "correcta": "C", "exp": "El supraespinoso es el tendón más frecuentemente lesionado porque transcurre por el espacio subacromial estrecho entre el acromion y la cabeza humeral, y presenta una zona crítica hipovascular (zona de Codman) a 1-2 cm de su inserción en el troquíter. Esta combinación de compresión mecánica e hipovascularidad favorece la degeneración y rotura."})

