if "musculos_ms" in BANCO and not any(q["enunciado"] == "Una mujer de 35 años acude tras una mastectomía radical derecha refiriendo dificultad para elevar el brazo por encima de la horizontal. En la exploración, al pedirle que empuje contra una pared, se objetiva una prominencia del borde medial de la escápula derecha (escápula alada). ¿Qué músculo está paralizado y cuál es el nervio lesionado?" for q in BANCO["musculos_ms"]["preguntas"]):
    BANCO["musculos_ms"]["preguntas"].append({"id": "musculos_ms_auto_68318813", "concepto": "parálisis nervio torácico largo", "enunciado": "Una mujer de 35 años acude tras una mastectomía radical derecha refiriendo dificultad para elevar el brazo por encima de la horizontal. En la exploración, al pedirle que empuje contra una pared, se objetiva una prominencia del borde medial de la escápula derecha (escápula alada). ¿Qué músculo está paralizado y cuál es el nervio lesionado?", "opciones": {"A": "Trapecio, por lesión del nervio accesorio espinal (XI par)", "B": "Romboides mayor, por lesión del nervio dorsal de la escápula", "C": "Serrato anterior, por lesión del nervio torácico largo de Bell", "D": "Dorsal ancho, por lesión del nervio toracodorsal"}, "correcta": "C", "exp": "El serrato anterior (inervado por el nervio torácico largo de Bell, ramas C5-C7) fija la escápula a la pared torácica y permite su rotación superior para elevar el brazo por encima de 90°; su lesión produce escápula alada clásica. Este nervio es vulnerable en la mastectomía radical y en la disección axilar por su trayecto superficial sobre el serrato."})
if "musculos_ms" in BANCO and not any(q["enunciado"] == "Un paciente con sospecha de lesión del nervio cubital es explorado mediante el signo de Froment: al sujetar una hoja de papel entre el pulgar y el índice, flexiona la falange distal del pulgar de forma compensatoria. ¿Qué músculo está siendo sustituido y cuál realiza la compensación?" for q in BANCO["musculos_ms"]["preguntas"]):
    BANCO["musculos_ms"]["preguntas"].append({"id": "musculos_ms_auto_cf97912e", "concepto": "test de Froment nervio cubital", "enunciado": "Un paciente con sospecha de lesión del nervio cubital es explorado mediante el signo de Froment: al sujetar una hoja de papel entre el pulgar y el índice, flexiona la falange distal del pulgar de forma compensatoria. ¿Qué músculo está siendo sustituido y cuál realiza la compensación?", "opciones": {"A": "Se sustituye el abductor corto del pulgar (mediano) por el flexor largo del pulgar (interóseo anterior)", "B": "Se sustituye el aductor del pulgar (cubital) por el flexor largo del pulgar (mediano)", "C": "Se sustituye el oponente del pulgar (mediano) por el extensor largo del pulgar (radial)", "D": "Se sustituye el flexor corto del pulgar (mediano) por el aductor del pulgar (cubital)"}, "correcta": "B", "exp": "El aductor del pulgar está inervado por el nervio cubital (rama profunda), por lo que en su lesión el paciente compensa la pinza activando el flexor largo del pulgar, inervado por el nervio interóseo anterior (rama del mediano), produciendo la flexión característica de la IF del pulgar. Este signo es muy sensible para detectar parálisis cubital distal."})

