# AUTO 2026-06-20 — disco_intervertebral
if "disco_intervertebral" in BANCO and not any(q["enunciado"] == "Un paciente de 60 años presenta degeneración discal lumbar con pérdida de altura del disco L4-L5. La degeneración se debe principalmente a la disminución del contenido de agua del núcleo pulposo con la edad. ¿Cuál es el componente molecular responsable de la elevada hidratación del núcleo pulposo en el adulto joven?" for q in BANCO["disco_intervertebral"]["preguntas"]):
    BANCO["disco_intervertebral"]["preguntas"].append({"id": "disco_intervertebral_auto_ca82f9e4", "concepto": "composición núcleo pulposo", "enunciado": "Un paciente de 60 años presenta degeneración discal lumbar con pérdida de altura del disco L4-L5. La degeneración se debe principalmente a la disminución del contenido de agua del núcleo pulposo con la edad. ¿Cuál es el componente molecular responsable de la elevada hidratación del núcleo pulposo en el adulto joven?", "opciones": {"A": "Fibras de colágeno tipo I dispuestas en láminas concéntricas", "B": "Proteoglicanos ricos en agrecano y condroitín sulfato", "C": "Fibras elásticas de elastina y fibrilina", "D": "Hidroxiapatita cálcica intersticial"}, "correcta": "B", "exp": "El núcleo pulposo es rico en proteoglicanos (especialmente agrecano con cadenas de condroitín y queratán sulfato) que retienen agua por su carga negativa, confiriéndole propiedades hidrófilas y de amortiguación. Con la edad disminuyen los proteoglicanos, perdiendo capacidad de hidratación y altura discal."})
if "disco_intervertebral" in BANCO and not any(q["enunciado"] == "Un varón de 38 años presenta lumbociática con dolor irradiado por cara posterior del muslo y pantorrilla hasta el talón y planta del pie, debilidad para la flexión plantar y abolición del reflejo aquíleo. La RM muestra una hernia discal posterolateral. ¿Qué disco y qué raíz están afectados con mayor probabilidad?" for q in BANCO["disco_intervertebral"]["preguntas"]):
    BANCO["disco_intervertebral"]["preguntas"].append({"id": "disco_intervertebral_auto_1b48ca2b", "concepto": "raíz comprimida hernia discal", "enunciado": "Un varón de 38 años presenta lumbociática con dolor irradiado por cara posterior del muslo y pantorrilla hasta el talón y planta del pie, debilidad para la flexión plantar y abolición del reflejo aquíleo. La RM muestra una hernia discal posterolateral. ¿Qué disco y qué raíz están afectados con mayor probabilidad?", "opciones": {"A": "Hernia L3-L4 que comprime la raíz L4", "B": "Hernia L4-L5 que comprime la raíz L4", "C": "Hernia L5-S1 que comprime la raíz S1", "D": "Hernia L5-S1 que comprime la raíz L5"}, "correcta": "C", "exp": "El cuadro (dolor por cara posterior de pierna hasta planta, debilidad de flexión plantar y abolición del aquíleo) corresponde a la raíz S1, comprimida típicamente por una hernia posterolateral L5-S1. En la columna lumbar, una hernia posterolateral comprime la raíz que desciende (la del nivel inferior), no la que sale por ese mismo foramen."})

